{
  "name": "Nexus Study Assistant",
  "description": "An AI-powered study companion that generates personalized study schedules, creates active recall quizzes, and provides evidence-based learning strategies."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Difficulty {
  Easy = 'Easy',
  Medium = 'Medium',
  Hard = 'Hard',
}

export interface Subject {
  id: string;
  name: string;
  difficulty: Difficulty;
}

export interface StudySession {
  day: string;
  subject: string;
  topic: string;
  technique: string;
  durationMinutes: number;
}

export interface StudyPlan {
  weeklyGoal: string;
  sessions: StudySession[];
}

export interface QuizQuestion {
  question: string;
  options: string[];
  correctIndex: number;
  explanation: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  const prompt = `
    Create a detailed weekly study schedule for a student.
    Subjects: ${subjectsStr}
    Available study time: ${hoursPerDay} hours per day.
    Focus Goal: ${focusArea}

    Assign specific study techniques (e.g., Pomodoro, Feynman Technique, Active Recall, Spaced Repetition) suitable for the difficulty and subject.
    Break down time into sessions between 30-90 minutes.
    Ensure 'day' is a string like "Monday", "Tuesday", etc.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: "A motivational summary of the week's goal" },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING },
                subject: { type: Type.STRING },
                topic: { type: Type.STRING, description: "Specific topic to cover" },
                technique: { type: Type.STRING, description: "Study method to use" },
                durationMinutes: { type: Type.NUMBER }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes"]
            }
          }
        },
        required: ["weeklyGoal", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as StudyPlan;
};

export const generateQuiz = async (topic: string, difficulty: string): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";
  const prompt = `Generate 5 multiple-choice questions about "${topic}" at a ${difficulty} level to test active recall. Include clear explanations.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Array of 4 possible answers" },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct answer (0-3)" },
            explanation: { type: Type.STRING }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as QuizQuestion[];
};

export const getStudyAdvice = async (query: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: `Provide concise, actionable, and scientific study advice for: "${query}". Keep it under 150 words.`,
  });

  return response.text || "Could not retrieve advice.";
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {
  const baseStyles = "px-4 py-2 rounded-lg font-medium transition-all duration-200 flex items-center justify-center gap-2 focus:outline-none focus:ring-2 focus:ring-offset-2";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500 shadow-md hover:shadow-lg",
    secondary: "bg-white text-slate-700 border border-slate-200 hover:bg-slate-50 focus:ring-slate-400 shadow-sm",
    danger: "bg-red-50 text-red-600 hover:bg-red-100 focus:ring-red-400 border border-red-100",
    ghost: "bg-transparent text-slate-600 hover:bg-slate-100 focus:ring-slate-300",
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${isLoading || disabled ? 'opacity-70 cursor-not-allowed' : ''} ${className}`}
      disabled={isLoading || disabled}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      )}
      {children}
    </button>
  );
};

import React, { useState } from 'react';
import { Subject, Difficulty, StudyPlan } from '../types';
import { generateStudyPlan } from '../services/geminiService';
import { Plus, Trash2, Calendar, Clock, BookOpen, Activity } from 'lucide-react';
import { Button } from './ui/Button';

export const StudyPlanner: React.FC = () => {
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [newSubject, setNewSubject] = useState('');
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
  const [hours, setHours] = useState(2);
  const [focus, setFocus] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<StudyPlan | null>(null);
  const [error, setError] = useState<string | null>(null);

  const addSubject = () => {
    if (!newSubject.trim()) return;
    const subject: Subject = {
      id: Date.now().toString(),
      name: newSubject,
      difficulty,
    };
    setSubjects([...subjects, subject]);
    setNewSubject('');
  };

  const removeSubject = (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
  };

  const handleGenerate = async () => {
    if (subjects.length === 0) {
      setError("Please add at least one subject.");
      return;
    }
    setError(null);
    setIsLoading(true);
    try {
      const generatedPlan = await generateStudyPlan(subjects, hours, focus || 'General Mastery');
      setPlan(generatedPlan);
    } catch (err) {
      setError("Failed to generate plan. Please try again.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Input Section */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
            <BookOpen className="w-5 h-5 text-indigo-600" />
            Setup Your Plan
          </h2>

          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Add Subject</label>
              <div className="flex gap-2">
                <input
                  type="text"
                  value={newSubject}
                  onChange={(e) => setNewSubject(e.target.value)}
                  placeholder="e.g. Calculus"
                  className="flex-1 px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all"
                  onKeyDown={(e) => e.key === 'Enter' && addSubject()}
                />
                <select
                  value={difficulty}
                  onChange={(e) => setDifficulty(e.target.value as Difficulty)}
                  className="px-3 py-2 border border-slate-300 rounded-lg bg-slate-50 text-sm focus:ring-indigo-500 outline-none"
                >
                  <option value={Difficulty.Easy}>Easy</option>
                  <option value={Difficulty.Medium}>Medium</option>
                  <option value={Difficulty.Hard}>Hard</option>
                </select>
                <Button onClick={addSubject} className="!px-3">
                  <Plus className="w-5 h-5" />
                </Button>
              </div>
            </div>

            {subjects.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {subjects.map(sub => (
                  <span key={sub.id} className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-xs font-medium ${
                    sub.difficulty === Difficulty.Hard ? 'bg-red-50 text-red-700 border border-red-100' :
                    sub.difficulty === Difficulty.Medium ? 'bg-yellow-50 text-yellow-700 border border-yellow-100' :
                    'bg-green-50 text-green-700 border border-green-100'
                  }`}>
                    {sub.name}
                    <button onClick={() => removeSubject(sub.id)} className="hover:text-red-600 ml-1">
                      <Trash2 className="w-3 h-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Daily Study Hours: {hours}h</label>
              <input
                type="range"
                min="1"
                max="12"
                step="0.5"
                value={hours}
                onChange={(e) => setHours(parseFloat(e.target.value))}
                className="w-full h-2 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
              />
              <div className="flex justify-between text-xs text-slate-500 mt-1">
                <span>1h</span>
                <span>12h</span>
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Goal / Focus Area</label>
              <input
                type="text"
                value={focus}
                onChange={(e) => setFocus(e.target.value)}
                placeholder="e.g. Prepare for finals next week"
                className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              />
            </div>

            {error && <p className="text-red-500 text-sm">{error}</p>}

            <Button onClick={handleGenerate} isLoading={isLoading} className="w-full mt-4">
              Generate Timetable
            </Button>
          </div>
        </div>
      </div>

      {/* Output Section */}
      <div className="lg:col-span-8">
        {plan ? (
          <div className="space-y-6 animate-fade-in">
            <div className="bg-indigo-600 text-white p-6 rounded-2xl shadow-lg">
              <h3 className="text-2xl font-bold mb-2">Weekly Plan</h3>
              <p className="opacity-90">{plan.weeklyGoal}</p>
            </div>

            <div className="grid gap-4">
              {['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'].map(day => {
                const daySessions = plan.sessions.filter(s => s.day.includes(day));
                if (daySessions.length === 0) return null;

                return (
                  <div key={day} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100">
                    <h4 className="text-lg font-bold text-slate-800 mb-3 border-b pb-2">{day}</h4>
                    <div className="space-y-3">
                      {daySessions.map((session, idx) => (
                        <div key={idx} className="flex flex-col sm:flex-row sm:items-center gap-3 p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-indigo-200 transition-colors">
                          <div className="flex items-center gap-2 min-w-[140px]">
                            <span className="bg-indigo-100 text-indigo-700 p-2 rounded-lg">
                              <BookOpen className="w-4 h-4" />
                            </span>
                            <span className="font-semibold text-slate-800">{session.subject}</span>
                          </div>

                          <div className="flex-1">
                            <p className="text-sm text-slate-600 font-medium">{session.topic}</p>
                            <div className="flex items-center gap-2 text-xs text-slate-500 mt-1">
                              <Activity className="w-3 h-3 text-emerald-500" />
                              <span>{session.technique}</span>
                            </div>
                          </div>

                          <div className="flex items-center gap-1 text-slate-500 text-sm bg-white px-3 py-1 rounded border border-slate-200">
                            <Clock className="w-3 h-3" />
                            {session.durationMinutes}m
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-400 p-12 bg-white rounded-2xl border border-dashed border-slate-300">
            <Calendar className="w-16 h-16 mb-4 opacity-50" />
            <p className="text-lg font-medium">No plan generated yet</p>
            <p className="text-sm">Add subjects and click generate to start studying effectively.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { generateQuiz } from '../services/geminiService';
import { QuizQuestion, Difficulty } from '../types';
import { Button } from './ui/Button';
import { Brain, CheckCircle, XCircle, ChevronRight, RefreshCw, Trophy } from 'lucide-react';

export const QuizMode: React.FC = () => {
  const [topic, setTopic] = useState('');
  const [questions, setQuestions] = useState<QuizQuestion[]>([]);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [score, setScore] = useState(0);
  const [selectedOption, setSelectedOption] = useState<number | null>(null);
  const [showExplanation, setShowExplanation] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
  const [quizFinished, setQuizFinished] = useState(false);

  const startQuiz = async () => {
    if (!topic.trim()) return;
    setIsLoading(true);
    setQuizFinished(false);
    setScore(0);
    setCurrentIndex(0);
    setQuestions([]);

    try {
      const qs = await generateQuiz(topic, difficulty);
      setQuestions(qs);
    } catch (e) {
      console.error(e);
      alert("Could not generate quiz. Try again.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAnswer = (index: number) => {
    if (selectedOption !== null) return; // Prevent changing answer
    setSelectedOption(index);
    setShowExplanation(true);

    if (index === questions[currentIndex].correctIndex) {
      setScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    setSelectedOption(null);
    setShowExplanation(false);
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setQuizFinished(true);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl shadow-sm border border-slate-100">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mb-4"></div>
        <p className="text-slate-600 font-medium">Generating smart questions...</p>
      </div>
    );
  }

  if (quizFinished) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl shadow-sm border border-slate-100 p-8 text-center animate-fade-in">
        <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mb-6">
            <Trophy className="w-10 h-10 text-yellow-600" />
        </div>
        <h3 className="text-2xl font-bold text-slate-800 mb-2">Quiz Complete!</h3>
        <p className="text-slate-600 mb-6 text-lg">You scored <span className="font-bold text-indigo-600">{score}</span> out of <span className="font-bold text-indigo-600">{questions.length}</span></p>

        <div className="flex gap-4">
            <Button onClick={() => setQuestions([])} variant="secondary">Back to Setup</Button>
            <Button onClick={startQuiz}>Try Again</Button>
        </div>
      </div>
    );
  }

  if (questions.length === 0) {
    return (
      <div className="max-w-xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-slate-100 text-center">
        <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center mx-auto mb-4">
          <Brain className="w-8 h-8 text-indigo-600" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">Active Recall Quiz</h2>
        <p className="text-slate-500 mb-8">Test your knowledge with AI-generated questions tailored to your study material.</p>

        <div className="space-y-4 text-left">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Subject / Topic</label>
            <input 
              type="text" 
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              placeholder="e.g. Photosynthesis, WW2, Linear Algebra"
              className="w-full px-4 py-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              onKeyDown={(e) => e.key === 'Enter' && startQuiz()}
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Difficulty</label>
            <div className="grid grid-cols-3 gap-2">
              {[Difficulty.Easy, Difficulty.Medium, Difficulty.Hard].map(d => (
                <button
                  key={d}
                  onClick={() => setDifficulty(d)}
                  className={`py-2 rounded-lg text-sm font-medium transition-colors border ${
                    difficulty === d 
                    ? 'bg-indigo-50 border-indigo-200 text-indigo-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                  }`}
                >
                  {d}
                </button>
              ))}
            </div>
          </div>

          <Button onClick={startQuiz} className="w-full py-3 text-lg mt-4">Start Quiz</Button>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentIndex];

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-6 flex justify-between items-center text-sm font-medium text-slate-500">
        <span>Question {currentIndex + 1} of {questions.length}</span>
        <span className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-xs">Score: {score}</span>
      </div>

      <div className="bg-white p-6 sm:p-8 rounded-2xl shadow-md border border-slate-100">
        <h3 className="text-xl font-semibold text-slate-900 mb-6 leading-relaxed">
            {currentQ.question}
        </h3>

        <div className="space-y-3">
          {currentQ.options.map((option, idx) => {
            let stateClass = "border-slate-200 hover:bg-slate-50 hover:border-slate-300";
            if (selectedOption !== null) {
                if (idx === currentQ.correctIndex) stateClass = "bg-green-50 border-green-200 text-green-800";
                else if (idx === selectedOption) stateClass = "bg-red-50 border-red-200 text-red-800";
                else stateClass = "opacity-50 border-slate-100";
            }

            return (
              <button
                key={idx}
                onClick={() => handleAnswer(idx)}
                disabled={selectedOption !== null}
                className={`w-full text-left p-4 rounded-xl border-2 transition-all flex justify-between items-center ${stateClass}`}
              >
                <span>{option}</span>
                {selectedOption !== null && idx === currentQ.correctIndex && <CheckCircle className="w-5 h-5 text-green-600" />}
                {selectedOption !== null && idx === selectedOption && idx !== currentQ.correctIndex && <XCircle className="w-5 h-5 text-red-600" />}
              </button>
            );
          })}
        </div>

        {showExplanation && (
          <div className="mt-6 bg-blue-50 p-4 rounded-xl border border-blue-100 animate-fade-in">
            <h4 className="font-semibold text-blue-900 mb-1 flex items-center gap-2">
                <Brain className="w-4 h-4" /> Explanation
            </h4>
            <p className="text-blue-800 text-sm leading-relaxed">{currentQ.explanation}</p>
          </div>
        )}

        <div className="mt-8 flex justify-end">
          <Button 
            onClick={nextQuestion} 
            disabled={selectedOption === null}
            className="w-full sm:w-auto"
          >
            {currentIndex === questions.length - 1 ? 'Finish Quiz' : 'Next Question'} 
            <ChevronRight className="w-4 h-4" />
          </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { getStudyAdvice } from '../services/geminiService';
import { ChatMessage } from '../types';
import { Send, Lightbulb, User, Sparkles } from 'lucide-react';
import { Button } from './ui/Button';

export const TipsAgent: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: "Hi! I'm your study coach. Ask me about time management, note-taking techniques, or how to beat procrastination!" }
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const responseText = await getStudyAdvice(input);
      const botMsg: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: responseText };
      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      const errorMsg: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: "Sorry, I'm having trouble thinking right now. Try again later." };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto h-[600px] flex flex-col bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
      <div className="bg-indigo-50 p-4 border-b border-indigo-100 flex items-center gap-3">
        <div className="bg-indigo-100 p-2 rounded-full">
            <Sparkles className="w-5 h-5 text-indigo-600" />
        </div>
        <div>
            <h3 className="font-bold text-indigo-900">Study Coach AI</h3>
            <p className="text-xs text-indigo-700">Ask about techniques, stress, or scheduling</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-200' : 'bg-indigo-600'}`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-slate-600" /> : <Lightbulb className="w-4 h-4 text-white" />}
            </div>
