import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  const prompt = `
    Create a detailed weekly study schedule for a Sri Lankan student.
    Subjects: ${subjectsStr}
    Available study time: ${hoursPerDay} hours per day.
    Focus Goal: ${focusArea}

    IMPORTANT: Generate all the content (Subject names, Topic descriptions, Techniques, Weekly Goal, etc.) in Sinhala language (Sinhala Unicode).

    Assign specific study techniques (e.g., Pomodoro, Feynman Technique, Active Recall) suitable for the difficulty and subject. Translate the technique names to Sinhala if possible or use common terms.
    Break down time into sessions between 30-90 minutes.
    Ensure 'day' is a string in Sinhala (e.g., "සඳුදා", "අඟහරුවාදා").
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: "A motivational summary of the week's goal in Sinhala" },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, description: "Day of the week in Sinhala" },
                subject: { type: Type.STRING, description: "Subject name in Sinhala" },
                topic: { type: Type.STRING, description: "Specific topic to cover in Sinhala" },
                technique: { type: Type.STRING, description: "Study method to use in Sinhala" },
                durationMinutes: { type: Type.NUMBER }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes"]
            }
          }
        },
        required: ["weeklyGoal", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as StudyPlan;
};

export const generateQuiz = async (topic: string, difficulty: string): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";
  const prompt = `Generate 5 multiple-choice questions about "${topic}" at a ${difficulty} level to test active recall. 
  IMPORTANT: Generate the questions, options, and explanations in Sinhala language (Sinhala Unicode). 
  Ensure technical terms are used correctly in the Sri Lankan educational context.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING, description: "Question text in Sinhala" },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Array of 4 possible answers in Sinhala" },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct answer (0-3)" },
            explanation: { type: Type.STRING, description: "Explanation in Sinhala" }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as QuizQuestion[];
};

