      return;
    }
    setError(null);
    setIsLoading(true);
    try {
      const generatedPlan = await generateStudyPlan(subjects, hours, focus || 'සාමාන්‍ය අධ්‍යයනය');
      setPlan(generatedPlan);
    } catch (err) {
      setError("සැලැස්ම සෑදීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
      {/* Input Section */}
      <div className="lg:col-span-4 space-y-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
