                // Simple partial match for Sinhala day names generated by AI
                const daySessions = plan.sessions.filter(s => s.day.includes(day) || s.day === day);
                // Also check if the AI returned English days just in case, or variations
                const englishDays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
                const dayIndex = ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා'].indexOf(day);
                const englishDay = englishDays[dayIndex];

                const combinedSessions = [...daySessions, ...plan.sessions.filter(s => s.day.includes(englishDay))];
                // Remove duplicates based on topic if any
                const uniqueSessions = Array.from(new Set(combinedSessions.map(s => s.topic))).map(topic => {
                    return combinedSessions.find(s => s.topic === topic)!;
                });

                if (uniqueSessions.length === 0) return null;

                return (
                  <div key={day} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100">
                    <h4 className="text-lg font-bold text-slate-800 mb-3 border-b pb-2">{day}</h4>
