  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
  const [quizFinished, setQuizFinished] = useState(false);

  const startQuiz = async () => {
    if (!topic.trim()) return;
    setIsLoading(true);
    setQuizFinished(false);
    setScore(0);
    setCurrentIndex(0);
    setQuestions([]);

    try {
      const qs = await generateQuiz(topic, difficulty);
      setQuestions(qs);
    } catch (e) {
      console.error(e);
      alert("ප්‍රශ්න පත්‍රය සෑදීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAnswer = (index: number) => {
    if (selectedOption !== null) return; // Prevent changing answer
    setSelectedOption(index);
    setShowExplanation(true);

    if (index === questions[currentIndex].correctIndex) {
      setScore(s => s + 1);
    }
  };

  const nextQuestion = () => {
    setSelectedOption(null);
    setShowExplanation(false);
    if (currentIndex < questions.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      setQuizFinished(true);
    }
  };

  if (isLoading) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl shadow-sm border border-slate-100">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mb-4"></div>
        <p className="text-slate-600 font-medium">AI විසින් ප්‍රශ්න සකසමින් පවතී...</p>
      </div>
    );
  }

  if (quizFinished) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[400px] bg-white rounded-2xl shadow-sm border border-slate-100 p-8 text-center animate-fade-in">
        <div className="w-20 h-20 bg-yellow-100 rounded-full flex items-center justify-center mb-6">
            <Trophy className="w-10 h-10 text-yellow-600" />
        </div>
        <h3 className="text-2xl font-bold text-slate-800 mb-2">අභ්‍යාසය අවසන්!</h3>
        <p className="text-slate-600 mb-6 text-lg">ඔබේ ලකුණු: <span className="font-bold text-indigo-600">{questions.length}</span> න් <span className="font-bold text-indigo-600">{score}</span> යි.</p>

        <div className="flex gap-4">
            <Button onClick={() => setQuestions([])} variant="secondary">නැවත සකසන්න</Button>
            <Button onClick={startQuiz}>යළි උත්සාහ කරන්න</Button>
        </div>
      </div>
    );
  }

  if (questions.length === 0) {
    return (
      <div className="max-w-xl mx-auto bg-white p-8 rounded-2xl shadow-sm border border-slate-100 text-center">
        <div className="w-16 h-16 bg-indigo-50 rounded-full flex items-center justify-center mx-auto mb-4">
          <Brain className="w-8 h-8 text-indigo-600" />
        </div>
        <h2 className="text-2xl font-bold text-slate-800 mb-2">දැනුම මනින අභ්‍යාස</h2>
        <p className="text-slate-500 mb-8">ඔබේ විෂය නිර්දේශයට අදාළව AI මගින් සකසන ලද ප්‍රශ්න පත්‍රයක් ලබාගන්න.</p>

        <div className="space-y-4 text-left">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">විෂය / මාතෘකාව</label>
            <input 
              type="text" 
              value={topic}
              onChange={(e) => setTopic(e.target.value)}
              placeholder="උදා: ප්‍රභාසංස්ලේෂණය, දෙවන ලෝක යුද්ධය"
              className="w-full px-4 py-3 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
              onKeyDown={(e) => e.key === 'Enter' && startQuiz()}
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">අසීරුතාව (Difficulty)</label>
            <div className="grid grid-cols-3 gap-2">
              {[Difficulty.Easy, Difficulty.Medium, Difficulty.Hard].map(d => (
                <button
                  key={d}
                  onClick={() => setDifficulty(d)}
                  className={`py-2 rounded-lg text-sm font-medium transition-colors border ${
                    difficulty === d 
                    ? 'bg-indigo-50 border-indigo-200 text-indigo-700' 
                    : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                  }`}
                >
                  {d === Difficulty.Easy ? 'ලේසි' : d === Difficulty.Medium ? 'සාමාන්‍ය' : 'අමාරු'}
                </button>
              ))}
            </div>
          </div>

          <Button onClick={startQuiz} className="w-full py-3 text-lg mt-4">ප්‍රශ්න විචාරය අරඹන්න</Button>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentIndex];

  return (
    <div className="max-w-2xl mx-auto">
      <div className="mb-6 flex justify-between items-center text-sm font-medium text-slate-500">
        <span>ප්‍රශ්නය {currentIndex + 1} / {questions.length}</span>
        <span className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-xs">ලකුණු: {score}</span>
      </div>

      <div className="bg-white p-6 sm:p-8 rounded-2xl shadow-md border border-slate-100">
        <h3 className="text-xl font-semibold text-slate-900 mb-6 leading-relaxed">
            {currentQ.question}
        </h3>

        <div className="space-y-3">
          {currentQ.options.map((option, idx) => {
            let stateClass = "border-slate-200 hover:bg-slate-50 hover:border-slate-300";
            if (selectedOption !== null) {
                if (idx === currentQ.correctIndex) stateClass = "bg-green-50 border-green-200 text-green-800";
                else if (idx === selectedOption) stateClass = "bg-red-50 border-red-200 text-red-800";
                else stateClass = "opacity-50 border-slate-100";
            }

            return (
              <button
                key={idx}
                onClick={() => handleAnswer(idx)}
                disabled={selectedOption !== null}
                className={`w-full text-left p-4 rounded-xl border-2 transition-all flex justify-between items-center ${stateClass}`}
              >
                <span>{option}</span>
                {selectedOption !== null && idx === currentQ.correctIndex && <CheckCircle className="w-5 h-5 text-green-600" />}
                {selectedOption !== null && idx === selectedOption && idx !== currentQ.correctIndex && <XCircle className="w-5 h-5 text-red-600" />}
              </button>
            );
          })}
        </div>

        {showExplanation && (
          <div className="mt-6 bg-blue-50 p-4 rounded-xl border border-blue-100 animate-fade-in">
            <h4 className="font-semibold text-blue-900 mb-1 flex items-center gap-2">
                <Brain className="w-4 h-4" /> පැහැදිලි කිරීම
            </h4>
            <p className="text-blue-800 text-sm leading-relaxed">{currentQ.explanation}</p>
          </div>
        )}

        <div className="mt-8 flex justify-end">
          <Button 
            onClick={nextQuestion} 
            disabled={selectedOption === null}
            className="w-full sm:w-auto"
          >
            {currentIndex === questions.length - 1 ? 'අවසානයි' : 'ඊළඟ ප්‍රශ්නය'} 
            <ChevronRight className="w-4 h-4" />
          </Button>
        </div>
      </div>
    </div>
  );
};

