export const TipsAgent: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', role: 'model', text: "ආයුබෝවන්! මම ඔබේ පාඩම් සහායකයා. කාල කළමනාකරණය, පාඩම් කරන ක්‍රම හෝ විභාගවලට මුහුණ දෙන ආකාරය ගැන ඕනෑම දෙයක් මගෙන් අසන්න." }
