      const errorMsg: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: "සමාවන්න, මට දැන් පිළිතුරු දීමට නොහැක. කරුණාකර මද වේලාවකින් උත්සාහ කරන්න." };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsTyping(false);
