        <div>
            <h3 className="font-bold text-indigo-900">AI පාඩම් සහායක</h3>
            <p className="text-xs text-indigo-700">අධ්‍යාපනික උපදෙස් ලබාගන්න</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50" ref={scrollRef}>
        {messages.map((msg) => (
          <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
            <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-slate-200' : 'bg-indigo-600'}`}>
              {msg.role === 'user' ? <User className="w-4 h-4 text-slate-600" /> : <Lightbulb className="w-4 h-4 text-white" />}
            </div>
            <div className={`max-w-[80%] p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-white text-slate-800 border border-slate-200 rounded-tr-none' 
                : 'bg-indigo-600 text-white rounded-tl-none'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isTyping && (
          <div className="flex gap-3">
            <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center flex-shrink-0">
               <Lightbulb className="w-4 h-4 text-white" />
            </div>
            <div className="bg-indigo-600 p-4 rounded-2xl rounded-tl-none flex items-center gap-1 h-10">
              <span className="w-1.5 h-1.5 bg-white rounded-full animate-bounce"></span>
