import React, { useState } from 'react';
import { Subject, Difficulty, StudyPlan } from '../types';
import { generateStudyPlan } from '../services/geminiService';
import { Plus, Trash2, Calendar, Clock, BookOpen, Activity } from 'lucide-react';
import { Button } from './ui/Button';

export const StudyPlanner: React.FC = () => {
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [newSubject, setNewSubject] = useState('');
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
  const [hours, setHours] = useState(2);
  const [focus, setFocus] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<StudyPlan | null>(null);
  const [error, setError] = useState<string | null>(null);

  const addSubject = () => {
    if (!newSubject.trim()) return;
    const subject: Subject = {
      id: Date.now().toString(),
      name: newSubject,
      difficulty,
    };
    setSubjects([...subjects, subject]);
    setNewSubject('');
  };

  const removeSubject = (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
  };

  const handleGenerate = async () => {
    if (subjects.length === 0) {
      setError("කරුණාකර අවම වශයෙන් එක් විෂයක්වත් ඇතුළත් කරන්න.");
      return;
    }
    setError(null);
    setIsLoading(true);
    try {
      const generatedPlan = await generateStudyPlan(subjects, hours, focus || 'සාමාන්‍ය අධ්‍යයනය');
      setPlan(generatedPlan);
    } catch (err) {
      setError("සැලැස්ම සෑදීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න.");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
