                // Simple partial match for Sinhala day names generated by AI
                const daySessions = plan.sessions.filter(s => s.day.includes(day) || s.day === day);
                // Also check if the AI returned English days just in case, or variations
                const englishDays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
                const dayIndex = ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා'].indexOf(day);
                const englishDay = englishDays[dayIndex];

                const combinedSessions = [...daySessions, ...plan.sessions.filter(s => s.day.includes(englishDay))];
                // Remove duplicates based on topic if any
                const uniqueSessions = Array.from(new Set(combinedSessions.map(s => s.topic))).map(topic => {
                    return combinedSessions.find(s => s.topic === topic)!;
                });

                if (uniqueSessions.length === 0) return null;

                return (
                  <div key={day} className="bg-white p-5 rounded-xl shadow-sm border border-slate-100">
                    <h4 className="text-lg font-bold text-slate-800 mb-3 border-b pb-2">{day}</h4>
                    <div className="space-y-3">
                      {uniqueSessions.map((session, idx) => (
                        <div key={idx} className="flex flex-col sm:flex-row sm:items-center gap-3 p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-indigo-200 transition-colors">
                          <div className="flex items-center gap-2 min-w-[140px]">
                            <span className="bg-indigo-100 text-indigo-700 p-2 rounded-lg">
                              <BookOpen className="w-4 h-4" />
                            </span>
                            <span className="font-semibold text-slate-800">{session.subject}</span>
                          </div>

                          <div className="flex-1">
                            <p className="text-sm text-slate-600 font-medium">{session.topic}</p>
                            <div className="flex items-center gap-2 text-xs text-slate-500 mt-1">
                              <Activity className="w-3 h-3 text-emerald-500" />
                              <span>{session.technique}</span>
                            </div>
                          </div>

                          <div className="flex items-center gap-1 text-slate-500 text-sm bg-white px-3 py-1 rounded border border-slate-200">
                            <Clock className="w-3 h-3" />
                            {session.durationMinutes}m
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="h-full flex flex-col items-center justify-center text-slate-400 p-12 bg-white rounded-2xl border border-dashed border-slate-300">
            <Calendar className="w-16 h-16 mb-4 opacity-50" />
            <p className="text-lg font-medium">තවමත් සැලැස්මක් සකසා නොමැත</p>
            <p className="text-sm text-center">ඔබේ විෂයයන් ඇතුළත් කර "කාලසටහන සාදන්න" ක්ලික් කරන්න.</p>
          </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  const prompt = `
    Acting as an expert in the Sri Lankan National School Curriculum (National Institute of Education - NIE), create a detailed weekly study schedule for a student in ${grade}.
    Subjects: ${subjectsStr}
    Available study time: ${hoursPerDay} hours per day.
    Focus Goal: ${focusArea}

    IMPORTANT INSTRUCTIONS:
    1. Base the "topic" for each session STRICTLY on the real chapters and units found in the standard Sri Lankan government Sinhala textbooks for ${grade} for these subjects.
    2. Generate ALL content (Subject names, Topic descriptions, Techniques, Weekly Goal, etc.) in Sinhala language (Sinhala Unicode).
    3. Be specific. Instead of just saying "Science", mention the specific Unit name from the textbook (e.g., "විද්‍යාව - 10 ශ්‍රේණිය - නිව්ටන්ගේ නියම").

    Assign specific study techniques (e.g., Pomodoro, Feynman Technique, Active Recall) suitable for the difficulty and subject. Translate the technique names to Sinhala if possible.
    Break down time into sessions between 30-90 minutes.
    Ensure 'day' is a string in Sinhala (e.g., "සඳුදා", "අඟහරුවාදා").
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: "A motivational summary of the week's goal in Sinhala" },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, description: "Day of the week in Sinhala" },
                subject: { type: Type.STRING, description: "Subject name in Sinhala" },
                topic: { type: Type.STRING, description: "Specific textbook chapter/topic in Sinhala" },
                technique: { type: Type.STRING, description: "Study method in Sinhala" },
                durationMinutes: { type: Type.NUMBER }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes"]
            }
          }
        },
        required: ["weeklyGoal", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as StudyPlan;
};

export const generateQuiz = async (topic: string, difficulty: string, grade: string): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";
  const prompt = `Generate 5 multiple-choice questions about "${topic}" suitable for a Sri Lankan student in ${grade}. 

  INSTRUCTIONS:
  1. Base the questions strictly on the content found in the standard Sri Lankan Sinhala school textbooks (NIE Syllabus) for ${grade}.
  2. IMPORTANT: Generate the questions, options, and explanations in Sinhala language (Sinhala Unicode). 
  3. Ensure technical terms are used correctly as they appear in the Sinhala textbooks.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING, description: "Question text in Sinhala" },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Array of 4 possible answers in Sinhala" },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct answer (0-3)" },
            explanation: { type: Type.STRING, description: "Explanation in Sinhala" }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as QuizQuestion[];
};

export const getStudyAdvice = async (query: string): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";
  const response = await ai.models.generateContent({
    model,
    contents: `Provide concise, actionable, and scientific study advice for: "${query}". 
    IMPORTANT: Provide the response in Sinhala language (Sinhala Unicode). Keep it friendly and encouraging for a Sri Lankan student. Keep it under 150 words.`,
  });

  return response.text || "උපදෙස් ලබා ගැනීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න.";
};

import React, { useState } from 'react';
