}

export const TipsAgent: React.FC<TipsAgentProps> = ({ language }) => {
  const t = {
    si: {
      welcome: "ආයුබෝවන්! මම ඔබේ පාඩම් සහායකයා. කාල කළමනාකරණය, පාඩම් කරන ක්‍රම හෝ විභාගවලට මුහුණ දෙන ආකාරය ගැන ඕනෑම දෙයක් මගෙන් අසන්න.",
