      error: "සමාවන්න, මට දැන් පිළිතුරු දීමට නොහැක. කරුණාකර මද වේලාවකින් උත්සාහ කරන්න."
    },
    en: {
      welcome: "Hello! I am your study assistant. Ask me anything about time management, study techniques, or exam preparation.",
      title: "AI Study Assistant",
      subtitle: "Get educational advice",
      placeholder: "What is the best way to study?",
      error: "Sorry, I cannot answer right now. Please try again later."
    }
  }[language];

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize or reset welcome message when language changes
  useEffect(() => {
    setMessages([{ id: 'init', role: 'model', text: t.welcome }]);
  }, [language]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: input };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
      const responseText = await getStudyAdvice(input, language);
      const botMsg: ChatMessage = { id: (Date.now() + 1).toString(), role: 'model', text: responseText };
      setMessages(prev => [...prev, botMsg]);
