                const daySessions = plan.sessions.filter(s => 
                  s.day.toLowerCase().includes(englishDay.toLowerCase()) || 
                  s.day.includes(sinhalaDay) || 
                  s.day === day
                );

                const uniqueSessions = Array.from(new Set(daySessions.map(s => s.topic))).map(topic => {
                    return daySessions.find(s => s.topic === topic)!;
                });

                if (uniqueSessions.length === 0) return null;

                return (
                  <div key={day} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
