                    </h4>
                    <div className="space-y-3">
                      {uniqueSessions.map((session, idx) => (
                        <div key={idx} className="group relative overflow-hidden bg-slate-50 p-4 rounded-xl border border-slate-200 hover:border-indigo-200 transition-all">
                          <div className="absolute top-0 left-0 w-1 h-full bg-indigo-500 group-hover:bg-indigo-600 transition-colors"></div>

                          <div className="flex flex-col sm:flex-row gap-3 relative z-10 pl-3">
                            <div className="flex items-start gap-3 sm:w-1/3">
                                <span className="bg-white p-2 rounded-lg shadow-sm border border-slate-100">
                                    <BookOpen className="w-5 h-5 text-indigo-600" />
                                </span>
                                <div>
                                    <p className="font-bold text-slate-800">{session.subject}</p>
                                    <p className="text-xs text-slate-500 mt-1 flex items-center gap-1 bg-white inline-flex px-2 py-0.5 rounded border border-slate-100">
                                        <Clock className="w-3 h-3" />
                                        {session.durationMinutes} min
                                    </p>
                                </div>
                            </div>

                            <div className="flex-1 sm:border-l sm:border-slate-200 sm:pl-4">
                              <p className="text-sm font-medium text-slate-700 mb-1">{session.topic}</p>
                              <div className="flex items-center gap-2">
                                <span className="text-xs font-semibold text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md">
                                    {session.technique}
                                </span>
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-slate-400 p-8 bg-white/50 rounded-3xl border-2 border-dashed border-slate-200 hover:border-slate-300 transition-colors">
