                <Calendar className="w-10 h-10 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-600 mb-2">{t.noPlan}</h3>
            <p className="text-slate-500 text-center max-w-xs">{t.noPlanDesc}</p>
          </div>
        )}
      </div>
    </div>
  );
};

