      focusLabel: "ප්‍රධාන ඉලක්කය",
      focusPlaceholder: "උදා: වාර විභාගයට සූදානම් වීම",
      generateBtn: "කාලසටහන සාදන්න",
      weeklyPlan: "සතිපතා සැලැස්ම",
      noPlan: "සැලැස්මක් සකසා නැත",
      noPlanDesc: "ඉහත විස්තර පුරවා 'කාලසටහන සාදන්න' ඔබන්න.",
      errorEmpty: "කරුණාකර විෂයයන් කිහිපයක් එකතු කරන්න.",
      errorGen: "සැලැස්ම සෑදීමට දෝෂයක්. නැවත උත්සාහ කරන්න.",
      easy: "ලේසි",
      medium: "සාමාන්‍ය",
      hard: "අමාරු",
      tipsTitle: "විශේෂ උපදෙස්",
      days: ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා']
    },
    en: {
      title: "Study Plan",
      subtitle: "Customize your schedule",
      selectGrade: "Grade",
      enterSubject: "Add Subjects",
      subjectPlaceholder: "Subject (Ex: Math)",
      addBtn: "Add",
      hoursLabel: "Daily Study Hours",
      focusLabel: "Main Goal",
      focusPlaceholder: "Ex: Term Test Prep",
      generateBtn: "Generate Schedule",
      weeklyPlan: "Your Weekly Plan",
      noPlan: "No plan generated",
      noPlanDesc: "Fill in the details above and generate your plan.",
      errorEmpty: "Please add at least one subject.",
      errorGen: "Could not generate plan. Please try again.",
      easy: "Easy",
      medium: "Medium",
      hard: "Hard",
      tipsTitle: "Pro Tips",
      days: ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    }
  }[language];

  const grades = [
    "6 ශ්‍රේණිය (Grade 6)", "7 ශ්‍රේණිය (Grade 7)", "8 ශ්‍රේණිය (Grade 8)", 
    "9 ශ්‍රේණිය (Grade 9)", "10 ශ්‍රේණිය (Grade 10)", "11 ශ්‍රේණිය (Grade 11)",
    "12 ශ්‍රේණිය (Grade 12)", "13 ශ්‍රේණිය (Grade 13)"
  ];

