    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 pb-20 lg:pb-0">
      {/* Input Section */}
      <div className="lg:col-span-4 space-y-5">
        <div className="bg-white p-4 sm:p-5 rounded-3xl shadow-lg shadow-indigo-100/50 border border-slate-100">
          <div className="mb-5">
            <h2 className="text-lg font-bold text-slate-800 flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-indigo-600" />
              {t.title}
            </h2>
            <p className="text-xs text-slate-500">{t.subtitle}</p>
          </div>

          <div className="space-y-4">
            {/* Grade Selection */}
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">{t.selectGrade}</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <GraduationCap className="h-4 w-4 text-indigo-400" />
                </div>
                <select
                  value={grade}
                  onChange={(e) => setGrade(e.target.value)}
                  className="w-full pl-9 pr-4 py-2.5 bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm text-slate-700 font-medium appearance-none transition-all hover:bg-slate-100"
                >
                  {grades.map(g => (
                    <option key={g} value={g}>{g}</option>
                  ))}
                </select>
                <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                   <span className="text-slate-400 text-[10px]">▼</span>
                </div>
              </div>
            </div>

            {/* Subject Input */}
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">{t.enterSubject}</label>
              <div className="flex flex-col gap-2.5">
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <BookOpen className="h-4 w-4 text-indigo-400" />
                  </div>
                  <input
                    type="text"
                    value={newSubject}
                    onChange={(e) => setNewSubject(e.target.value)}
                    placeholder={t.subjectPlaceholder}
                    className="w-full pl-9 pr-4 py-2.5 bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm text-slate-700 placeholder-slate-400 transition-all hover:bg-slate-100"
                    onKeyDown={(e) => e.key === 'Enter' && addSubject()}
                  />
                </div>

                <div className="flex gap-2">
                  <div className="relative flex-1">
                     <select
                      value={difficulty}
                      onChange={(e) => setDifficulty(e.target.value as Difficulty)}
                      className="w-full pl-9 pr-8 py-2.5 bg-slate-50 border-0 rounded-xl text-sm font-medium text-slate-700 focus:ring-2 focus:ring-indigo-500 appearance-none hover:bg-slate-100"
                    >
                      <option value={Difficulty.Easy}>{t.easy}</option>
                      <option value={Difficulty.Medium}>{t.medium}</option>
                      <option value={Difficulty.Hard}>{t.hard}</option>
                    </select>
                    <Activity className="absolute left-3 top-3 w-4 h-4 text-indigo-400 pointer-events-none" />
                  </div>

                  <Button onClick={addSubject} className="aspect-square !p-0 w-[42px] h-[42px] rounded-xl flex items-center justify-center shrink-0 bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200">
                    <Plus className="w-5 h-5" />
                  </Button>
                </div>
              </div>
            </div>

            {/* Tags Display */}
            {subjects.length > 0 && (
              <div className="flex flex-wrap gap-2 p-2.5 bg-slate-50 rounded-xl border border-slate-100 min-h-[50px]">
                {subjects.map(sub => (
                  <span key={sub.id} className={`inline-flex items-center gap-1 px-2.5 py-1 rounded-lg text-xs font-medium shadow-sm transition-transform hover:scale-105 ${
                    sub.difficulty === Difficulty.Hard ? 'bg-white text-rose-600 border border-rose-100' :
                    sub.difficulty === Difficulty.Medium ? 'bg-white text-amber-600 border border-amber-100' :
                    'bg-white text-emerald-600 border border-emerald-100'
                  }`}>
                    {sub.name}
                    <button onClick={() => removeSubject(sub.id)} className="text-slate-400 hover:text-red-500 transition-colors">
                      <X className="w-3 h-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}

            {/* Hours Slider */}
            <div>
              <div className="flex justify-between items-center mb-1.5">
                 <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">{t.hoursLabel}</label>
                 <span className="text-indigo-600 font-bold bg-indigo-50 px-2 py-0.5 rounded text-xs">{hours}h</span>
              </div>
              <input
                type="range"
                min="1"
                max="12"
                step="0.5"
                value={hours}
                onChange={(e) => setHours(parseFloat(e.target.value))}
                className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
              />
            </div>

            {/* Focus Input */}
            <div>
              <label className="block text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-1.5">{t.focusLabel}</label>
