                  <Target className="h-4 w-4 text-indigo-400" />
                </div>
                <input
                  type="text"
                  value={focus}
                  onChange={(e) => setFocus(e.target.value)}
                  placeholder={t.focusPlaceholder}
                  className="w-full pl-9 pr-4 py-2.5 bg-slate-50 border-0 rounded-xl focus:ring-2 focus:ring-indigo-500 text-sm text-slate-700 placeholder-slate-400 transition-all hover:bg-slate-100"
                />
              </div>
            </div>

            {error && <p className="text-rose-500 text-xs font-medium bg-rose-50 p-2.5 rounded-lg flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-rose-500" />{error}</p>}

            <Button 
                onClick={handleGenerate} 
                isLoading={isLoading} 
                className="w-full py-3.5 rounded-xl text-base shadow-lg shadow-indigo-200 hover:shadow-indigo-300 transform hover:-translate-y-0.5 transition-all bg-gradient-to-r from-indigo-600 to-purple-600 border-0 mt-2"
            >
              {t.generateBtn}
            </Button>
          </div>
        </div>
      </div>

      {/* Output Section */}
      <div className="lg:col-span-8">
        {plan ? (
          <div className="space-y-6 animate-fade-in">
            {/* Goal Card */}
            <div className="bg-gradient-to-br from-indigo-600 to-purple-700 text-white p-6 sm:p-8 rounded-3xl shadow-xl shadow-indigo-200 relative overflow-hidden">
              <div className="relative z-10">
                <div className="flex items-center gap-3 mb-3 opacity-90">
                    <div className="p-2 bg-white/20 rounded-lg backdrop-blur-sm">
                        <Target className="w-5 h-5 text-white" />
                    </div>
                    <h3 className="text-lg font-medium">{t.weeklyPlan}</h3>
                </div>
                <p className="text-2xl sm:text-3xl font-bold leading-tight">{plan.weeklyGoal}</p>
              </div>
              {/* Decorative circles */}
              <div className="absolute top-0 right-0 -mt-10 -mr-10 w-40 h-40 bg-white/10 rounded-full blur-2xl"></div>
              <div className="absolute bottom-0 left-0 -mb-10 -ml-10 w-32 h-32 bg-purple-500/20 rounded-full blur-2xl"></div>
            </div>

            {/* Tips Card */}
            {plan.tips && plan.tips.length > 0 && (
               <div className="bg-emerald-50/80 backdrop-blur-sm border border-emerald-100 p-6 rounded-3xl">
                  <h3 className="font-bold text-emerald-800 mb-4 flex items-center gap-2">
                    <Lightbulb className="w-5 h-5 text-emerald-600" />
                    {t.tipsTitle}
                  </h3>
                  <div className="grid gap-3">
                    {plan.tips.map((tip, i) => (
                        <div key={i} className="flex gap-3 bg-white p-3 rounded-xl shadow-sm border border-emerald-100/50">
                            <span className="flex-shrink-0 w-6 h-6 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center text-xs font-bold">{i + 1}</span>
                            <p className="text-emerald-900 text-sm leading-relaxed">{tip}</p>
                        </div>
                    ))}
                  </div>
               </div>
            )}

            {/* Weekly Schedule */}
            <div className="grid gap-4">
              {t.days.map(day => {
                const englishDay = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'][t.days.indexOf(day)];
                const sinhalaDay = ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා'][t.days.indexOf(day)];

                const daySessions = plan.sessions.filter(s => 
                  s.day.toLowerCase().includes(englishDay.toLowerCase()) || 
                  s.day.includes(sinhalaDay) || 
                  s.day === day
                );

                const uniqueSessions = Array.from(new Set(daySessions.map(s => s.topic))).map(topic => {
                    return daySessions.find(s => s.topic === topic)!;
                });

                if (uniqueSessions.length === 0) return null;

                return (
                  <div key={day} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 hover:shadow-md transition-shadow">
                    <h4 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                        <Calendar className="w-5 h-5 text-indigo-500" />
                        {day}
                    </h4>
                    <div className="space-y-3">
                      {uniqueSessions.map((session, idx) => (
                        <div key={idx} className="group relative overflow-hidden bg-slate-50 p-4 rounded-xl border border-slate-200 hover:border-indigo-200 transition-all">
                          <div className="absolute top-0 left-0 w-1 h-full bg-indigo-500 group-hover:bg-indigo-600 transition-colors"></div>

                          <div className="flex flex-col sm:flex-row gap-3 relative z-10 pl-3">
                            <div className="flex items-start gap-3 sm:w-1/3">
                                <span className="bg-white p-2 rounded-lg shadow-sm border border-slate-100">
                                    <BookOpen className="w-5 h-5 text-indigo-600" />
                                </span>
                                <div>
                                    <p className="font-bold text-slate-800">{session.subject}</p>
                                    <p className="text-xs text-slate-500 mt-1 flex items-center gap-1 bg-white inline-flex px-2 py-0.5 rounded border border-slate-100">
                                        <Clock className="w-3 h-3" />
                                        {session.durationMinutes} min
                                    </p>
                                </div>
                            </div>

                            <div className="flex-1 sm:border-l sm:border-slate-200 sm:pl-4">
                              <p className="text-sm font-medium text-slate-700 mb-1">{session.topic}</p>
                              <div className="flex items-center gap-2">
                                <span className="text-xs font-semibold text-indigo-600 bg-indigo-50 px-2 py-1 rounded-md">
                                    {session.technique}
                                </span>
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
          <div className="h-full min-h-[400px] flex flex-col items-center justify-center text-slate-400 p-8 bg-white/50 rounded-3xl border-2 border-dashed border-slate-200 hover:border-slate-300 transition-colors">
            <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                <Calendar className="w-10 h-10 text-slate-300" />
            </div>
            <h3 className="text-xl font-bold text-slate-600 mb-2">{t.noPlan}</h3>
            <p className="text-slate-500 text-center max-w-xs">{t.noPlanDesc}</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Subject, Difficulty, StudyPlan, Language } from '../types';
import { generateStudyPlan } from '../services/geminiService';
import { Plus, Trash2, Calendar, Clock, BookOpen, Activity, GraduationCap, Lightbulb, Target, Sparkles, X } from 'lucide-react';
import { Button } from './ui/Button';

interface StudyPlannerProps {
  language: Language;
}

export const StudyPlanner: React.FC<StudyPlannerProps> = ({ language }) => {
  const [subjects, setSubjects] = useState<Subject[]>([]);
  const [newSubject, setNewSubject] = useState('');
  const [difficulty, setDifficulty] = useState<Difficulty>(Difficulty.Medium);
  const [hours, setHours] = useState(2);
  const [grade, setGrade] = useState('10 ශ්‍රේණිය (Grade 10)');
  const [focus, setFocus] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [plan, setPlan] = useState<StudyPlan | null>(null);
  const [error, setError] = useState<string | null>(null);

  const t = {
    si: {
      title: "පාඩම් සැලැස්ම",
      subtitle: "ඔබේ කාලසටහන සකසාගන්න",
      selectGrade: "ශ්‍රේණිය",
      enterSubject: "විෂය ඇතුළත් කරන්න",
      subjectPlaceholder: "විෂය (උදා: ගණිතය)",
      addBtn: "එකතු කරන්න",
      hoursLabel: "දිනකට පැය ගණන",
      focusLabel: "ප්‍රධාන ඉලක්කය",
      focusPlaceholder: "උදා: වාර විභාගය",
      generateBtn: "කාලසටහන සාදන්න",
      weeklyPlan: "සතිපතා සැලැස්ම",
      noPlan: "සැලැස්මක් සකසා නැත",
      noPlanDesc: "ඉහත විස්තර පුරවා 'කාලසටහන සාදන්න' ඔබන්න.",
      errorEmpty: "කරුණාකර විෂයයන් කිහිපයක් එකතු කරන්න.",
      errorGen: "සැලැස්ම සෑදීමට දෝෂයක්. නැවත උත්සාහ කරන්න.",
      easy: "ලේසි",
      medium: "සාමාන්‍ය",
      hard: "අමාරු",
      tipsTitle: "විශේෂ උපදෙස්",
      days: ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා']
    },
    en: {
      title: "Study Plan",
      subtitle: "Customize your schedule",
      selectGrade: "Grade",
      enterSubject: "Add Subjects",
      subjectPlaceholder: "Subject (Ex: Math)",
      addBtn: "Add",
      hoursLabel: "Daily Hours",
      focusLabel: "Main Goal",
      focusPlaceholder: "Ex: Term Test",
      generateBtn: "Generate Schedule",
      weeklyPlan: "Your Weekly Plan",
      noPlan: "No plan generated",
      noPlanDesc: "Fill in the details above and generate your plan.",
      errorEmpty: "Please add at least one subject.",
      errorGen: "Could not generate plan. Please try again.",
      easy: "Easy",
      medium: "Medium",
      hard: "Hard",
      tipsTitle: "Pro Tips",
      days: ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']
    }
  }[language];

  const grades = [
    "6 ශ්‍රේණිය (Grade 6)", "7 ශ්‍රේණිය (Grade 7)", "8 ශ්‍රේණිය (Grade 8)", 
    "9 ශ්‍රේණිය (Grade 9)", "10 ශ්‍රේණිය (Grade 10)", "11 ශ්‍රේණිය (Grade 11)",
    "12 ශ්‍රේණිය (Grade 12)", "13 ශ්‍රේණිය (Grade 13)"
  ];

  const addSubject = () => {
    if (!newSubject.trim()) return;
    const subject: Subject = {
      id: Date.now().toString(),
      name: newSubject,
      difficulty,
    };
    setSubjects([...subjects, subject]);
    setNewSubject('');
  };

  const removeSubject = (id: string) => {
    setSubjects(subjects.filter(s => s.id !== id));
  };

  const handleGenerate = async () => {
    if (subjects.length === 0) {
      setError(t.errorEmpty);
      return;
    }
    setError(null);
    setIsLoading(true);
    try {
      const generatedPlan = await generateStudyPlan(
        subjects, 
        hours, 
        focus || (language === 'si' ? 'විෂය නිර්දේශය ආවරණය කිරීම' : 'Cover Syllabus'), 
        grade,
        language
      );
      setPlan(generatedPlan);
    } catch (err) {
      setError(t.errorGen);
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 pb-20 lg:pb-0">
      {/* Input Section */}
      <div className="lg:col-span-4">
        <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
          <div className="mb-4">
            <h2 className="text-base font-bold text-slate-800 flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-indigo-600" />
              {t.title}
            </h2>
            <p className="text-[11px] text-slate-400">{t.subtitle}</p>
          </div>

          <div className="space-y-3">
            {/* Grade Selection */}
            <div>
              <label className="block text-xs font-medium text-slate-500 mb-1">{t.selectGrade}</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none">
                  <GraduationCap className="h-3.5 w-3.5 text-indigo-400" />
                </div>
                <select
                  value={grade}
                  onChange={(e) => setGrade(e.target.value)}
                  className="w-full pl-8 pr-4 py-2 bg-slate-50 border-0 rounded-lg text-sm text-slate-700 font-medium focus:ring-1 focus:ring-indigo-500 transition-all hover:bg-slate-100/80"
                >
                  {grades.map(g => (
                    <option key={g} value={g}>{g}</option>
                  ))}
                </select>
                <div className="absolute inset-y-0 right-0 pr-2.5 flex items-center pointer-events-none">
                   <span className="text-slate-400 text-[10px]">▼</span>
                </div>
              </div>
            </div>

            {/* Subject Input */}
            <div>
              <label className="block text-xs font-medium text-slate-500 mb-1">{t.enterSubject}</label>
              <div className="flex flex-col gap-2">
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-2.5 flex items-center pointer-events-none">
                    <BookOpen className="h-3.5 w-3.5 text-indigo-400" />
                  </div>
                  <input
                    type="text"
                    value={newSubject}
                    onChange={(e) => setNewSubject(e.target.value)}
                    placeholder={t.subjectPlaceholder}
                    className="w-full pl-8 pr-3 py-2 bg-slate-50 border-0 rounded-lg text-sm text-slate-700 placeholder-slate-400 focus:ring-1 focus:ring-indigo-500 transition-all hover:bg-slate-100/80"
                    onKeyDown={(e) => e.key === 'Enter' && addSubject()}
                  />
                </div>

                <div className="flex gap-2">
                  <div className="relative flex-1">
                     <select
                      value={difficulty}
                      onChange={(e) => setDifficulty(e.target.value as Difficulty)}
                      className="w-full pl-8 pr-6 py-2 bg-slate-50 border-0 rounded-lg text-xs font-medium text-slate-600 focus:ring-1 focus:ring-indigo-500 appearance-none hover:bg-slate-100/80"
                    >
                      <option value={Difficulty.Easy}>{t.easy}</option>
                      <option value={Difficulty.Medium}>{t.medium}</option>
                      <option value={Difficulty.Hard}>{t.hard}</option>
                    </select>
                    <Activity className="absolute left-2.5 top-2.5 w-3.5 h-3.5 text-indigo-400 pointer-events-none" />
                  </div>

                  <Button onClick={addSubject} className="aspect-square !p-0 w-[36px] h-[36px] rounded-lg flex items-center justify-center shrink-0 bg-indigo-600 hover:bg-indigo-700 text-white shadow-sm">
                    <Plus className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            </div>

            {/* Tags Display */}
            {subjects.length > 0 && (
              <div className="flex flex-wrap gap-1.5 p-2 bg-slate-50/50 rounded-lg border border-slate-100/50 min-h-[40px]">
                {subjects.map(sub => (
                  <span key={sub.id} className={`inline-flex items-center gap-1 px-2 py-0.5 rounded text-[11px] font-medium border ${
                    sub.difficulty === Difficulty.Hard ? 'bg-white text-rose-600 border-rose-100' :
                    sub.difficulty === Difficulty.Medium ? 'bg-white text-amber-600 border-amber-100' :
                    'bg-white text-emerald-600 border-emerald-100'
                  }`}>
                    {sub.name}
                    <button onClick={() => removeSubject(sub.id)} className="text-slate-400 hover:text-red-500 transition-colors">
                      <X className="w-3 h-3" />
                    </button>
                  </span>
                ))}
              </div>
            )}

            {/* Hours Slider */}
            <div>
              <div className="flex justify-between items-center mb-1">
