import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const dayExample = language === 'si' ? '(e.g., "සඳුදා")' : '(e.g., "Monday")';

  const prompt = `
    Acting as an expert in the Sri Lankan National School Curriculum (National Institute of Education - NIE), create a detailed weekly study schedule for a student in ${grade}.
    Subjects: ${subjectsStr}
    Available study time: ${hoursPerDay} hours per day.
    Focus Goal: ${focusArea}

    IMPORTANT INSTRUCTIONS:
    1. Base the "topic" and "unitNumber" for each session STRICTLY on the REAL chapters and units found in the standard Sri Lankan government textbooks (${language === 'si' ? 'Sinhala Medium' : 'English Medium'}) for ${grade}. Do not hallucinate topics.
    2. You MUST provide the official Lesson/Unit Number (e.g. "05", "12") for every topic.
    3. Generate ALL content in ${langContext}.
    4. Be specific. Instead of just saying "Science", mention the specific Unit name from the textbook (e.g., "Unit 5: Newton's Laws").
    5. If a user provided subject matches a core subject (Maths, Science, History, Sinhala, English, Religion, etc.), use the exact syllabus topics.

    Assign specific study techniques (e.g., Pomodoro, Feynman Technique, Active Recall). Translate the technique names if in Sinhala.
    Break down time into sessions between 30-90 minutes.
    Ensure 'day' is a string in the target language ${dayExample}.
    Provide 3-5 actionable study tips specifically for these subjects.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: `A motivational summary of the week's goal in ${language === 'si' ? 'Sinhala' : 'English'}` },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }, 
            description: `List of 3-5 specific study tips in ${language === 'si' ? 'Sinhala' : 'English'} for the selected subjects` 
          },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, description: `Day of the week in ${language === 'si' ? 'Sinhala' : 'English'}` },
                subject: { type: Type.STRING, description: `Subject name in ${language === 'si' ? 'Sinhala' : 'English'}` },
                unitNumber: { type: Type.STRING, description: `The official Unit/Lesson Number (e.g., '05' or '10') from the textbook.` },
                topic: { type: Type.STRING, description: `Specific textbook chapter/topic name in ${language === 'si' ? 'Sinhala' : 'English'}` },
                technique: { type: Type.STRING, description: `Study method in ${language === 'si' ? 'Sinhala' : 'English'}` },
                durationMinutes: { type: Type.NUMBER }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes"]
            }
          }
        },
        required: ["weeklyGoal", "tips", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as StudyPlan;
};

export const generateQuiz = async (
  subject: string, 
  topic: string, 
  subTopic: string, 
  questionCount: number,
  difficulty: string, 
  grade: string, 
  language: Language
): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const langInstruction = language === 'si' 
    ? "Generate the questions, options, and explanations in Sinhala language (Sinhala Unicode)." 
    : "Generate the questions, options, and explanations in English language.";

  const medium = language === 'si' ? "Sinhala Medium" : "English Medium";

  const prompt = `Generate ${questionCount} multiple-choice questions suitable for a Sri Lankan student in ${grade}.
  Subject: ${subject}
  ${topic ? `Topic: ${topic}` : ''}
  ${subTopic ? `Sub-topic: ${subTopic}` : ''}

  INSTRUCTIONS:
  1. Base the questions strictly on the content found in the standard Sri Lankan school textbooks (NIE Syllabus - ${medium}) for ${grade}.
  2. IMPORTANT: ${langInstruction}
  3. Ensure technical terms are used correctly as they appear in the textbooks.
  4. Ensure there are exactly ${questionCount} questions.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING, description: `Question text in ${language === 'si' ? 'Sinhala' : 'English'}` },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, description: `Array of 4 possible answers in ${language === 'si' ? 'Sinhala' : 'English'}` },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct answer (0-3)" },
            explanation: { type: Type.STRING, description: `Explanation in ${language === 'si' ? 'Sinhala' : 'English'}` }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as QuizQuestion[];
};

export const getStudyAdvice = async (query: string, language: Language): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const langInstruction = language === 'si'
    ? "Provide the response in Sinhala language (Sinhala Unicode)."
    : "Provide the response in English language.";

  const response = await ai.models.generateContent({
    model,
    contents: `Provide concise, actionable, and scientific study advice for: "${query}". 
    IMPORTANT: ${langInstruction} Keep it friendly and encouraging for a Sri Lankan student. Keep it under 150 words.`,
  });

  return response.text || (language === 'si' ? "උපදෙස් ලබා ගැනීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න." : "Could not retrieve advice. Please try again.");
};

