               <div className="bg-emerald-50/50 backdrop-blur-sm border border-emerald-100/80 p-4 rounded-2xl">
                  <h3 className="font-bold text-emerald-800 text-sm mb-3 flex items-center gap-2">
                    <Lightbulb className="w-4 h-4 text-emerald-600" />
                    {t.tipsTitle}
                  </h3>
                  <div className="grid gap-2">
                    {plan.tips.map((tip, i) => (
                        <div key={i} className="flex gap-2 bg-white p-2.5 rounded-xl shadow-sm border border-emerald-100/50">
                            <span className="flex-shrink-0 w-5 h-5 bg-emerald-100 text-emerald-700 rounded-full flex items-center justify-center text-[10px] font-bold">{i + 1}</span>
                            <p className="text-emerald-900 text-xs leading-relaxed">{tip}</p>
                        </div>
                    ))}
                  </div>
               </div>
            )}

            {/* Weekly Schedule */}
            <div className="grid gap-3">
              {t.days.map(day => {
                const englishDay = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'][t.days.indexOf(day)];
                const sinhalaDay = ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා'][t.days.indexOf(day)];

                // Get study sessions for this day
                const daySessions = plan.sessions.filter(s => 
                  s.day.toLowerCase().includes(englishDay.toLowerCase()) || 
                  s.day.includes(sinhalaDay) || 
                  s.day === day
                );

                // Get busy slots for this day
                const dayBusySlots = busySlots.filter(s => 
                  s.day.toLowerCase() === englishDay.toLowerCase() || 
                  s.day === sinhalaDay
                );

                if (daySessions.length === 0 && dayBusySlots.length === 0) return null;

                const uniqueSessions = Array.from(new Set(daySessions.map(s => s.topic))).map(topic => {
                    return daySessions.find(s => s.topic === topic)!;
                });

                return (
                  <div key={day} className="bg-white p-4 rounded-xl shadow-sm border border-slate-100">
                    <h4 className="text-sm font-bold text-slate-800 mb-3 flex items-center gap-2">
                        <Calendar className="w-4 h-4 text-indigo-500" />
                        {day}
                    </h4>

                    {/* Display Busy Slots First or Interleaved - keeping it simple by just listing them */}
                    {dayBusySlots.map(slot => (
                       <div key={slot.id} className="mb-2 bg-slate-100/50 border border-slate-200/50 p-2 rounded-lg flex items-center gap-3 opacity-70 grayscale">
                          <div className="w-1 h-full bg-slate-400 rounded-full"></div>
                          <div className="flex-1">
                             <p className="text-xs font-bold text-slate-500">{slot.label}</p>
                             <p className="text-[10px] text-slate-400">{slot.startTime} - {slot.endTime}</p>
                          </div>
                          <Briefcase className="w-3 h-3 text-slate-400" />
                       </div>
                    ))}

                    <div className="space-y-2">
                      {uniqueSessions.map((session, idx) => (
                        <div key={idx} className="group relative overflow-hidden bg-slate-50 p-3 rounded-lg border border-slate-200/60 hover:border-indigo-200 transition-all">
                          <div className="absolute top-0 left-0 w-0.5 h-full bg-indigo-500 group-hover:bg-indigo-600 transition-colors"></div>

                          <div className="flex flex-col sm:flex-row gap-2 relative z-10 pl-2">
                            <div className="flex items-start gap-2 sm:w-1/3">
                                <div>
                                    <p className="font-bold text-slate-800 text-sm">{session.subject}</p>
                                    <p className="text-[10px] text-slate-500 mt-0.5 flex items-center gap-1">
                                        <Clock className="w-3 h-3" />
                                        {session.durationMinutes} min
                                    </p>
                                </div>
                            </div>

                            <div className="flex-1 sm:border-l sm:border-slate-200 sm:pl-3">
                              <div className="flex flex-wrap items-baseline gap-2 mb-1">
                                {session.unitNumber && (
                                    <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded uppercase tracking-wider whitespace-nowrap border border-indigo-100">
                                        {language === 'si' ? 'පාඩම' : 'Unit'} {session.unitNumber}
                                    </span>
                                )}
                                <p className="text-xs font-medium text-slate-700">{session.topic}</p>
                              </div>
                              <div className="flex items-center gap-2">
                                <span className={`text-[10px] font-semibold px-1.5 py-0.5 rounded border ${
                                  session.technique.toLowerCase().includes('review') || session.technique.toLowerCase().includes('spaced') 
                                  ? 'bg-amber-50 text-amber-700 border-amber-100' 
                                  : 'bg-indigo-50 text-indigo-600 border-indigo-100'
                                }`}>
                                    {session.technique}
                                </span>
                              </div>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>

            {/* Sources Section */}
            {plan.sourceUrls && plan.sourceUrls.length > 0 && (
              <div className="mt-4 p-4 bg-blue-50/50 rounded-xl border border-blue-100 text-xs text-blue-800">
                <p className="font-semibold mb-2 flex items-center gap-1">
                  <LinkIcon className="w-3 h-3" /> {t.sources}
                </p>
                <ul className="list-disc pl-4 space-y-1">
                  {plan.sourceUrls.map((url, i) => (
                    <li key={i}>
                      <a href={url} target="_blank" rel="noopener noreferrer" className="hover:underline truncate block max-w-full">
                        {url}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        ) : (
          <div className="h-full min-h-[300px] flex flex-col items-center justify-center text-slate-400 p-6 bg-white/50 rounded-2xl border-2 border-dashed border-slate-200 hover:border-slate-300 transition-colors">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4">
                <Calendar className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-bold text-slate-600 mb-1">{t.noPlan}</h3>
            <p className="text-xs text-slate-500 text-center max-w-xs">{t.noPlanDesc}</p>
