        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = []
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Format busy slots for the prompt
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed classes, student is free all day.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const dayExample = language === 'si' ? '(e.g., "සඳුදා")' : '(e.g., "Monday")';

  const prompt = `
    You are an expert on the Sri Lankan National Curriculum (NIE) and Cognitive Science (Memory optimization).
    Task: Create a highly effective weekly study schedule for a student in ${grade}.

    Student Context:
    - Subjects: ${subjectsStr}
    - Available study time: ${hoursPerDay} hours per day (outside of busy slots).
    - Focus Goal: ${focusArea}
    - **BUSY TIMES (DO NOT SCHEDULE STUDYING HERE):** ${busySlotsStr}

    Apply these MEMORY SCIENCE principles strictly:
    1. **Interleaving:** Do not schedule the same subject for long blocks. Mix subjects (e.g., Math -> Science -> History) to improve retention.
    2. **Spaced Repetition:** Schedule "Review" sessions for previous topics, not just new ones. Mark these as "Spaced Repetition".
    3. **Active Recall:** Assign techniques like "Practice Questions", "Past Papers", or "Blurting" instead of just "Reading".

    CRITICAL INSTRUCTIONS FOR ACCURACY:
    1. USE GOOGLE SEARCH to find the official Grade ${grade} syllabus or Teacher's Guides from 'nie.lk' or 'e-thaksalawa'.
    2. Extract the EXACT "Unit Number" and "Lesson Name" from the official curriculum.
    3. Generate ALL content in ${langContext}.

    Structure:
    - Assign specific units to days.
    - Provide the official Unit Number.
    - Break down time into sessions between 30-60 minutes (shorter is better for focus).
    - Ensure 'day' is a string in the target language ${dayExample}.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: `A motivational summary of the week's goal in ${language === 'si' ? 'Sinhala' : 'English'}` },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }, 
            description: `List of 3-5 specific study tips based on memory science in ${language === 'si' ? 'Sinhala' : 'English'}` 
          },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, description: `Day of the week in ${language === 'si' ? 'Sinhala' : 'English'}` },
                subject: { type: Type.STRING, description: `Subject name in ${language === 'si' ? 'Sinhala' : 'English'}` },
                unitNumber: { type: Type.STRING, description: `The official Unit/Lesson Number (e.g., '05')` },
                topic: { type: Type.STRING, description: `Specific textbook chapter/topic name` },
                technique: { type: Type.STRING, description: `Specific memory technique (e.g., Active Recall, Spaced Repetition)` },
                durationMinutes: { type: Type.NUMBER }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes"]
            }
          }
        },
        required: ["weeklyGoal", "tips", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  const plan = JSON.parse(text) as StudyPlan;

  // Extract source URLs from grounding metadata
  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  const chunks = groundingMetadata?.groundingChunks as any[] | undefined;
  const sources = chunks
    ?.map((chunk: any) => chunk.web?.uri)
    .filter((url: any): url is string => typeof url === 'string' && !!url);

  if (sources && sources.length > 0) {
    plan.sourceUrls = [...new Set(sources)];
  }

  return plan;
};

export const generateQuiz = async (
  subject: string, 
  topic: string, 
  subTopic: string, 
  questionCount: number,
  difficulty: string, 
  grade: string, 
