import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Format busy slots for the prompt
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed extra classes.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const dayExample = language === 'si' ? '(e.g., "සඳුදා")' : '(e.g., "Monday")';

  // Calculate time until exam to determine strategy
  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  let phaseInstruction = "";

  if (diffDays < 30) {
    phaseInstruction = "URGENT: The exam is in less than a month. Focus heavily on ACTIVE RECALL, PAST PAPERS, and MOCK EXAMS. Reduce passive reading.";
  } else if (diffDays < 90) {
    phaseInstruction = "CONSOLIDATION: The exam is 1-3 months away. Focus on connecting concepts, Spaced Repetition, and solving difficult problems.";
  } else {
    phaseInstruction = "FOUNDATION: The exam is far away. Focus on deep understanding of core concepts and creating high-quality notes.";
  }

  const prompt = `
    You are an expert on the Sri Lankan National Curriculum (NIE) and Cognitive Science.
    Task: Create a highly effective weekly study schedule for a student in ${grade}.

    CRITICAL TIME CONSTRAINTS (DO NOT VIOLATE):
    1. **School Home Time:** The student returns home at ${routine.schoolEndTime}. DO NOT schedule any study sessions before this time on Weekdays (Mon-Fri).
    2. **Bedtime:** The student sleeps at ${routine.bedTime}. DO NOT schedule any sessions after this time. Sleep is crucial for memory.
    3. **Classes:** ${busySlotsStr}. Do not overlap with these.
    4. **Study Duration:** Target ${hoursPerDay} hours of actual study time per day within the available window.

    EXAM CONTEXT:
    - Target Exam Date: ${routine.examDate} (${diffDays} days remaining).
    - Strategy: ${phaseInstruction}

    Apply these MEMORY SCIENCE principles:
    1. **Interleaving:** Mix subjects (e.g., Math -> Science) within the available evening window.
    2. **Spaced Repetition:** Schedule "Review" sessions.
    3. **Active Recall:** Assign techniques specifically based on the exam proximity mentioned above.

    INSTRUCTIONS FOR SYLLABUS ACCURACY:
    1. USE GOOGLE SEARCH to find the official Grade ${grade} syllabus (NIE/e-thaksalawa).
    2. Extract EXACT "Unit Number" and "Lesson Name".
    3. Generate content in ${langContext}.

    Structure:
    - Provide the study phase name (e.g., "Intensive Revision").
    - Break down time into sessions (30-50 mins) with 10 min breaks.
    - Ensure 'day' is a string in the target language ${dayExample}.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeklyGoal: { type: Type.STRING, description: `A motivational summary in ${language === 'si' ? 'Sinhala' : 'English'}` },
          studyPhase: { type: Type.STRING, description: `The name of the current study phase (e.g. Revision) in ${language === 'si' ? 'Sinhala' : 'English'}` },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING }, 
            description: `3 specific tips based on the calculated exam urgency and memory science in ${language === 'si' ? 'Sinhala' : 'English'}` 
          },
          sessions: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                day: { type: Type.STRING, description: `Day of the week` },
                subject: { type: Type.STRING, description: `Subject name` },
                unitNumber: { type: Type.STRING, description: `Unit Number` },
                topic: { type: Type.STRING, description: `Topic name` },
                technique: { type: Type.STRING, description: `Memory technique` },
                durationMinutes: { type: Type.NUMBER },
                startTime: { type: Type.STRING, description: "Suggested start time (e.g. '16:00')" }
              },
              required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
            }
          }
        },
        required: ["weeklyGoal", "studyPhase", "tips", "sessions"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  const plan = JSON.parse(text) as StudyPlan;

  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  const chunks = groundingMetadata?.groundingChunks as any[] | undefined;
  const sources = chunks
    ?.map((chunk: any) => chunk.web?.uri)
    .filter((url: any): url is string => typeof url === 'string' && !!url);

  if (sources && sources.length > 0) {
    plan.sourceUrls = [...new Set(sources)];
  }

  return plan;
};

