                             <p className="text-[10px] text-amber-600/70">{slot.startTime} - {slot.endTime}</p>
                          </div>
                          <Briefcase className="w-3 h-3 text-amber-400" />
                       </div>
                    ))}

                    <div className="space-y-2 mt-3">
                      {uniqueSessions.map((session, idx) => (
                        <div key={idx} className="group relative overflow-hidden bg-slate-50 p-3 rounded-lg border border-slate-200/60 hover:border-indigo-200 transition-all">
                          <div className="absolute top-0 left-0 w-0.5 h-full bg-indigo-500 group-hover:bg-indigo-600 transition-colors"></div>

                          <div className="flex flex-col sm:flex-row gap-2 relative z-10 pl-2">
                            <div className="flex items-start gap-2 sm:w-1/3">
                                <div>
                                    <p className="font-bold text-slate-800 text-sm">{session.subject}</p>
                                    <div className="flex items-center gap-2 mt-0.5">
                                      {session.startTime && (
                                        <p className="text-[10px] font-mono text-indigo-600 bg-indigo-50 px-1 rounded">{session.startTime}</p>
                                      )}
                                      <p className="text-[10px] text-slate-500 flex items-center gap-1">
                                          <Clock className="w-3 h-3" />
                                          {session.durationMinutes} min
                                      </p>
                                    </div>
                                </div>
                            </div>

                            <div className="flex-1 sm:border-l sm:border-slate-200 sm:pl-3">
                              <div className="flex flex-wrap items-baseline gap-2 mb-1">
                                {session.unitNumber && (
                                    <span className="text-[10px] font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded uppercase tracking-wider whitespace-nowrap border border-indigo-100">
                                        {language === 'si' ? 'පාඩම' : 'Unit'} {session.unitNumber}
                                    </span>
                                )}
                                <p className="text-xs font-medium text-slate-700">{session.topic}</p>
                              </div>
                              <div className="flex items-center gap-2">
                                <span className={`text-[10px] font-semibold px-1.5 py-0.5 rounded border ${
