                        <div className="grid gap-3">
                        {t.days.map(day => {
                            const englishDay = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'][t.days.indexOf(day)];
                            const sinhalaDay = ['සඳුදා', 'අඟහරුවාදා', 'බදාදා', 'බ්‍රහස්පතින්දා', 'සිකුරාදා', 'සෙනසුරාදා', 'ඉරිදා'][t.days.indexOf(day)];

                            // Get study sessions for this day in this week
                            const daySessions = week.sessions.filter(s => 
                              s.day.toLowerCase().includes(englishDay.toLowerCase()) || 
                              s.day.includes(sinhalaDay) || 
                              s.day === day
                            );

                            const dayBusySlots = busySlots.filter(s => 
                              s.day.toLowerCase() === englishDay.toLowerCase() || 
                              s.day === sinhalaDay
                            );

                            const isWeekend = englishDay === 'Saturday' || englishDay === 'Sunday';

                            if (daySessions.length === 0 && dayBusySlots.length === 0) return null;

                            // Sort
                            daySessions.sort((a, b) => (a.startTime || '').localeCompare(b.startTime || ''));

                             const uniqueSessions = Array.from(new Set(daySessions.map(s => s.topic))).map(topic => {
                                return daySessions.find(s => s.topic === topic)!;
                            });

                            return (
                                <div key={day} className="bg-white p-3 rounded-lg border border-slate-200">
                                    <h4 className="text-xs font-bold text-slate-800 mb-2 flex items-center gap-2">
                                        <div className="w-1.5 h-1.5 rounded-full bg-indigo-500"></div>
                                        {day}
                                    </h4>

                                    {/* Routine: School */}
                                    {!isWeekend && (
                                        <div className="mb-2 bg-slate-50 border border-slate-100 p-1.5 rounded flex items-center gap-2 opacity-60">
                                            <Home className="w-3 h-3 text-slate-400" />
                                            <span className="text-[10px] text-slate-400">School until {schoolEndTime}</span>
                                        </div>
                                    )}

                                    {/* Busy Slots */}
                                    {dayBusySlots.map(slot => (
                                        <div key={slot.id} className="mb-2 bg-amber-50 border border-amber-100 p-1.5 rounded flex items-center gap-2">
                                            <Briefcase className="w-3 h-3 text-amber-400" />
                                            <div className="flex-1 leading-none">
                                                <span className="text-[10px] font-bold text-amber-700">{slot.label}</span>
                                                <span className="text-[9px] text-amber-600/70 ml-2">{slot.startTime}-{slot.endTime}</span>
                                            </div>
                                        </div>
                                    ))}

                                    {/* Sessions */}
                                    <div className="space-y-2">
                                        {uniqueSessions.map((session, idx) => (
                                            <div key={idx} className="relative pl-3 border-l-2 border-indigo-100 py-1">
                                                <div className="flex flex-col">
                                                    <div className="flex justify-between items-start">
                                                       <span className="text-[11px] font-bold text-slate-700">{session.subject}</span>
                                                       {session.startTime && (
                                                         <span className="text-[9px] font-mono text-indigo-500 bg-indigo-50 px-1 rounded">{session.startTime}</span>
                                                       )}
                                                    </div>
                                                    <span className="text-[10px] text-slate-500">{session.topic}</span>
                                                    <div className="flex items-center gap-2 mt-1">
                                                        <span className="text-[9px] px-1.5 py-0.5 bg-slate-100 rounded text-slate-500">{session.durationMinutes}m</span>
                                                        <span className={`text-[9px] px-1.5 py-0.5 rounded ${
                                                            session.technique.includes('Review') ? 'bg-amber-50 text-amber-600' : 'bg-green-50 text-green-600'
                                                        }`}>{session.technique}</span>
                                                    </div>
                                                </div>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            );
                        })}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>

            {/* Sources Section */}
            {plan.sourceUrls && plan.sourceUrls.length > 0 && (
              <div className="mt-4 p-4 bg-blue-50/50 rounded-xl border border-blue-100 text-xs text-blue-800">
                <p className="font-semibold mb-2 flex items-center gap-1">
                  <LinkIcon className="w-3 h-3" /> {t.sources}
                </p>
                <ul className="list-disc pl-4 space-y-1">
                  {plan.sourceUrls.map((url, i) => (
                    <li key={i}>
                      <a href={url} target="_blank" rel="noopener noreferrer" className="hover:underline truncate block max-w-full">
                        {url}
                      </a>
                    </li>
                  ))}
                </ul>
              </div>
            )}
          </div>
        ) : (
          <div className="h-full min-h-[300px] flex flex-col items-center justify-center text-slate-400 p-6 bg-white/50 rounded-2xl border-2 border-dashed border-slate-200 hover:border-slate-300 transition-colors">
            <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-4">
                <Calendar className="w-8 h-8 text-slate-300" />
            </div>
            <h3 className="text-lg font-bold text-slate-600 mb-1">{t.noPlan}</h3>
            <p className="text-xs text-slate-500 text-center max-w-xs">{t.noPlanDesc}</p>
          </div>
        )}
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Format busy slots
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed extra classes.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const dayExample = language === 'si' ? '(e.g., "සඳුදා")' : '(e.g., "Monday")';

  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Calculate current grade number for progression logic
  const gradeMatch = grade.match(/(\d+)/);
  const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : null;
  const currentYear = today.getFullYear();

  // Generate up to 12 weeks (approx 3 months) to provide a fuller roadmap, while staying within token limits
  const weeksToGenerate = Math.min(Math.ceil(daysUntilExam / 7), 12);
  const currentFormattedDate = today.toISOString().split('T')[0];

  const prompt = `
    You are an expert on the Sri Lankan National Curriculum (NIE) and Cognitive Science.
    Task: Create a week-by-week study plan starting from ${currentFormattedDate} until the exam date ${routine.examDate}.

    Student Context:
    - Current Grade: ${grade} (Year: ${currentYear})
    - Subjects: ${subjectsStr}
    - Focus Goal: ${focusArea}
    - Weeks to Plan: ${weeksToGenerate} (If exam is further than ${weeksToGenerate} weeks, just plan the first ${weeksToGenerate} weeks).

    GRADE PROGRESSION LOGIC (CRITICAL):
    - The student is currently in Grade ${currentGradeNum || 'Unknown'}.
    - **Automatic Promotion:** On January 1st of any new year, the student AUTOMATICALLY promotes to the next grade (e.g., Grade ${currentGradeNum} -> Grade ${(currentGradeNum || 0) + 1}).
    - **Content Adaptation:** If the schedule generated below includes dates in a new year, you MUST select syllabus topics from the HIGHER grade level for those weeks.

    TIME CONSTRAINTS:
    1. **School Home Time:** Student is free after ${routine.schoolEndTime} on Weekdays.
    2. **Bedtime:** Student sleeps at ${routine.bedTime}.
    3. **Classes:** ${busySlotsStr}. Do not overlap.
    4. **Target:** ${hoursPerDay} hours/day.

    MEMORY SCIENCE STRATEGY:
    - **Foundation:** Early weeks or new grade content (Concepts, Notes).
    - **Consolidation:** Middle phase (Practice Questions).
    - **Revision:** Approaching exam (Past Papers, Mock Exams).

    INSTRUCTIONS:
    1. Generate a schedule for EACH of the ${weeksToGenerate} weeks.
    2. For each week, define the "Phase" and "Goal".
    3. Specific Syllabus: Use Google Search to find Grade ${currentGradeNum} (or ${currentGradeNum ? currentGradeNum + 1 : 'next'} if new year) units for the subjects.
    4. Language: ${langContext}.

    Output Format:
    JSON object with a "weeks" array. Each week has a specific start/end date, phase, goal, and an array of sessions.
    Ensure "date" in sessions matches the actual calendar date for that weekday.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                weekNumber: { type: Type.INTEGER },
                startDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                endDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                phase: { type: Type.STRING, description: "Study Phase Name" },
                goal: { type: Type.STRING, description: "Weekly Goal" },
                sessions: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      day: { type: Type.STRING },
                      date: { type: Type.STRING, description: "YYYY-MM-DD" },
                      subject: { type: Type.STRING },
                      topic: { type: Type.STRING },
                      unitNumber: { type: Type.STRING },
                      technique: { type: Type.STRING },
                      durationMinutes: { type: Type.NUMBER },
                      startTime: { type: Type.STRING }
                    },
                    required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
                  }
                }
              },
              required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
            }
          },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "General memory science tips for this exam journey" 
          }
        },
        required: ["weeks", "tips"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  const rawData = JSON.parse(text);

  const plan: StudyPlan = {
    examDate: routine.examDate,
    weeks: rawData.weeks,
    tips: rawData.tips,
  };

  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  const chunks = groundingMetadata?.groundingChunks as any[] | undefined;
  const sources = chunks
    ?.map((chunk: any) => chunk.web?.uri)
    .filter((url: any): url is string => typeof url === 'string' && !!url);

  if (sources && sources.length > 0) {
    plan.sourceUrls = [...new Set(sources)];
  }

  return plan;
};

