    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None'
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Format busy slots
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed extra classes.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Calculate current grade number for progression logic
  const gradeMatch = grade.match(/(\d+)/);
  const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : 0;
  const currentYear = today.getFullYear();

  const currentFormattedDate = today.toISOString().split('T')[0];

  // --- CONTEXT DETECTION LOGIC ---
  let examContextInstruction = "";
  const isLongDuration = daysUntilExam > 300; // Approx 10 months+

  if (isLongDuration) {
    if (currentGradeNum === 10 || currentGradeNum === 11) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Ordinary Level (O/L)**
        - The user is preparing for the O/L exam which covers TWO years of content.
        - **Year 1 Schedule:** Focus strictly on covering the GRADE 10 syllabus.
        - **Year 2 Schedule:** Focus strictly on covering the GRADE 11 syllabus + Revision of Grade 10.
        - Ensure the timeline transitions from Grade 10 topics to Grade 11 topics naturally.
      `;
    } else if (currentGradeNum === 12 || currentGradeNum === 13) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Advanced Level (A/L)**
        - The user is preparing for the A/L exam which covers TWO years of content.
        - **Year 1 Schedule:** Focus strictly on covering the GRADE 12 syllabus.
        - **Year 2 Schedule:** Focus strictly on covering the GRADE 13 syllabus + Revision of Grade 12.
        - Ensure the timeline transitions from Grade 12 topics to Grade 13 topics naturally.
      `;
    } else {
      examContextInstruction = `
        **EXAM CONTEXT: Long Term Promotion**
        - The exam is far away. 
        - Cover Grade ${currentGradeNum} content first.
        - Then automatically proceed to Grade ${currentGradeNum + 1} content when the timeline enters the next calendar year.
      `;
    }
  } else {
    examContextInstruction = `**EXAM CONTEXT:** Immediate/Short-term preparation for Grade ${currentGradeNum} exams.`;
  }

  const prompt = `
    You are an expert on the Sri Lankan National Curriculum (NIE) and Cognitive Science.
    Task: Create a COMPLETE, DETAILED study plan starting from ${currentFormattedDate} until the exam date ${routine.examDate}.

    Student Context:
    - Current Grade: ${grade} (Year: ${currentYear})
    - Subjects: ${subjectsStr}
    - Focus Goal: ${focusArea}
    - Rest Day Preference: ${restDay} (If "None", study everyday)

    ${examContextInstruction}

    FORMATTING INSTRUCTIONS:
    - **GENERATE DETAILED WEEKLY SCHEDULES FOR THE ENTIRE DURATION.**
    - Do NOT use "monthly blocks". Every item in the output array must represent a specific WEEK (Week 1, Week 2, Week 3, etc.).
    - Every week must have a specific "sessions" array with daily tasks just like the first week.
    - If the duration is very long (e.g., 2 years), you must optimize your JSON size to fit as many weeks as possible, but DO NOT compromise on the "Weekly" structure.

    TIME CONSTRAINTS:
    1. **School Home Time:** Free after ${routine.schoolEndTime}.
    2. **Bedtime:** Sleeps at ${routine.bedTime}.
    3. **Classes:** ${busySlotsStr}. Do not overlap.
    4. **Target:** ${hoursPerDay} hours/day.
    5. **Rest Day Logic:** If user selected a specific Rest Day (${restDay}), DO NOT schedule heavy study on that day. Leave it empty or assign light "Passive Review".

    MEMORY SCIENCE STRATEGY:
    - **Everyday Study:** If studying daily, ensure "Active Recall" is spaced out.
    - **Phase Names:** Foundation (Early) -> Consolidation (Mid) -> Revision (Final).

    INSTRUCTIONS:
    1. Use Google Search to find specific syllabus units for the detected Grades (e.g. Gr 10 & 11 for O/L).
    2. Language: ${langContext}.
    3. Output JSON with a "weeks" array.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                weekNumber: { type: Type.INTEGER },
                startDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                endDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                phase: { type: Type.STRING, description: "Study Phase Name" },
                goal: { type: Type.STRING, description: "Weekly Goal" },
                sessions: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      day: { type: Type.STRING },
                      date: { type: Type.STRING, description: "YYYY-MM-DD" },
                      subject: { type: Type.STRING },
                      topic: { type: Type.STRING },
                      unitNumber: { type: Type.STRING },
                      technique: { type: Type.STRING },
                      durationMinutes: { type: Type.NUMBER },
                      startTime: { type: Type.STRING }
                    },
                    required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
                  }
                }
              },
              required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
            }
          },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "General memory science tips for this exam journey" 
          }
        },
        required: ["weeks", "tips"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  const rawData = JSON.parse(text);

  const plan: StudyPlan = {
    examDate: routine.examDate,
    weeks: rawData.weeks,
    tips: rawData.tips,
  };

  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  const chunks = groundingMetadata?.groundingChunks as any[] | undefined;
  const sources = chunks
    ?.map((chunk: any) => chunk.web?.uri)
    .filter((url: any): url is string => typeof url === 'string' && !!url);

  if (sources && sources.length > 0) {
    plan.sourceUrls = [...new Set(sources)];
  }

  return plan;
};

export const generateQuiz = async (
  subject: string, 
  topic: string, 
  subTopic: string, 
  questionCount: number,
  difficulty: string, 
  grade: string, 
  language: Language
): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const langInstruction = language === 'si' 
    ? "Generate the questions, options, and explanations in Sinhala language (Sinhala Unicode)." 
    : "Generate the questions, options, and explanations in English language.";

  const medium = language === 'si' ? "Sinhala Medium" : "English Medium";

  const prompt = `Generate ${questionCount} multiple-choice questions suitable for a Sri Lankan student in ${grade}.
  Subject: ${subject}
  ${topic ? `Topic: ${topic}` : ''}
  ${subTopic ? `Sub-topic: ${subTopic}` : ''}

  INSTRUCTIONS:
  1. USE GOOGLE SEARCH to verify facts against the Grade ${grade} ${subject} syllabus (NIE Sri Lanka).
  2. Base the questions strictly on the content found in the standard Sri Lankan school textbooks (${medium}) for ${grade}.
  3. IMPORTANT: ${langInstruction}
  4. Ensure technical terms are used correctly as they appear in the textbooks.
  5. Ensure there are exactly ${questionCount} questions.`;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            question: { type: Type.STRING, description: `Question text in ${language === 'si' ? 'Sinhala' : 'English'}` },
            options: { type: Type.ARRAY, items: { type: Type.STRING }, description: `Array of 4 possible answers in ${language === 'si' ? 'Sinhala' : 'English'}` },
            correctIndex: { type: Type.INTEGER, description: "Index of the correct answer (0-3)" },
            explanation: { type: Type.STRING, description: `Explanation in ${language === 'si' ? 'Sinhala' : 'English'}` }
          },
          required: ["question", "options", "correctIndex", "explanation"]
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  return JSON.parse(text) as QuizQuestion[];
};

export const getStudyAdvice = async (query: string, language: Language): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  const model = "gemini-3-flash-preview";

  const langInstruction = language === 'si'
    ? "Provide the response in Sinhala language (Sinhala Unicode)."
    : "Provide the response in English language.";

  const response = await ai.models.generateContent({
    model,
    contents: `Provide concise, actionable, and scientific study advice for: "${query}". 
    IMPORTANT: ${langInstruction} Keep it friendly and encouraging for a Sri Lankan student. Keep it under 150 words.`,
  });

  return response.text || (language === 'si' ? "උපදෙස් ලබා ගැනීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න." : "Could not retrieve advice. Please try again.");
};

