  // Format busy slots
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed extra classes.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Calculate current grade number for progression logic
  const gradeMatch = grade.match(/(\d+)/);
  const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : 0;
  const currentYear = today.getFullYear();

  const currentFormattedDate = today.toISOString().split('T')[0];

  // --- CONTEXT DETECTION LOGIC ---
  let examContextInstruction = "";
  const isLongDuration = daysUntilExam > 300; // Approx 10 months+

  if (isLongDuration) {
    if (currentGradeNum === 10 || currentGradeNum === 11) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Ordinary Level (O/L)**
        - The user is preparing for the O/L exam which covers TWO years of content.
        - **Year 1 Schedule:** Focus strictly on covering the GRADE 10 syllabus.
        - **Year 2 Schedule:** Focus strictly on covering the GRADE 11 syllabus + Revision of Grade 10.
        - Ensure the timeline transitions from Grade 10 topics to Grade 11 topics naturally.
      `;
    } else if (currentGradeNum === 12 || currentGradeNum === 13) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Advanced Level (A/L)**
        - The user is preparing for the A/L exam which covers TWO years of content.
        - **Year 1 Schedule:** Focus strictly on covering the GRADE 12 syllabus.
        - **Year 2 Schedule:** Focus strictly on covering the GRADE 13 syllabus + Revision of Grade 12.
        - Ensure the timeline transitions from Grade 12 topics to Grade 13 topics naturally.
      `;
    } else {
      examContextInstruction = `
        **EXAM CONTEXT: Long Term Promotion**
        - The exam is far away. 
        - Cover Grade ${currentGradeNum} content first.
        - Then automatically proceed to Grade ${currentGradeNum + 1} content when the timeline enters the next calendar year.
      `;
    }
  } else {
    examContextInstruction = `**EXAM CONTEXT:** Immediate/Short-term preparation for Grade ${currentGradeNum} exams.`;
  }

  const prompt = `
    You are an expert on the Sri Lankan National Curriculum (NIE).
    Task: Create a **MASTER ROADMAP** from ${currentFormattedDate} until the exam date ${routine.examDate}.

    Student Context:
    - Grade: ${grade}
    - Subjects: ${subjectsStr}
    - Rest Day: ${restDay}

    ${examContextInstruction}

    **CRITICAL INSTRUCTION FOR TOKEN LIMIT MANAGEMENT:**
    1. You must output the FULL list of weeks (e.g., Week 1 to Week 104) covering the entire duration. **DO NOT SKIP WEEKS.**
    2. **Week 1 to Week 4:** Generate DETAILED 'sessions' arrays with daily tasks.
    3. **Week 5 to End:** Generate the 'weekNumber', 'startDate', 'endDate', 'phase', and 'goal'. **BUT leave the 'sessions' array EMPTY ([]).**
       - The user will generate the specific details for these weeks later on demand.
       - Ensure the 'goal' for these weeks is descriptive (e.g., "History Unit 5: Kotte Era & Math: Quadratic Equations").

    Instructions:
    1. Use Google Search to find specific syllabus units.
    2. Language: ${langContext}.
    3. Output JSON.
  `;

  const response = await ai.models.generateContent({
    model: MODEL_NAME,
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          weeks: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                weekNumber: { type: Type.INTEGER },
                startDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                endDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                phase: { type: Type.STRING, description: "Study Phase Name" },
                goal: { type: Type.STRING, description: "Weekly Goal" },
                sessions: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      day: { type: Type.STRING },
                      date: { type: Type.STRING, description: "YYYY-MM-DD" },
                      subject: { type: Type.STRING },
                      topic: { type: Type.STRING },
                      unitNumber: { type: Type.STRING },
                      technique: { type: Type.STRING },
                      durationMinutes: { type: Type.NUMBER },
                      startTime: { type: Type.STRING }
                    },
                    required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
                  }
                }
              },
              required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
            }
          },
          tips: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING },
            description: "General memory science tips for this exam journey" 
          }
        },
        required: ["weeks", "tips"]
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error("No response from AI");

  const rawData = JSON.parse(text);

  const plan: StudyPlan = {
    examDate: routine.examDate,
    weeks: rawData.weeks,
    tips: rawData.tips,
  };

  const groundingMetadata = response.candidates?.[0]?.groundingMetadata;
  const chunks = groundingMetadata?.groundingChunks as any[] | undefined;
  const sources = chunks
    ?.map((chunk: any) => chunk.web?.uri)
    .filter((url: any): url is string => typeof url === 'string' && !!url);

  if (sources && sources.length > 0) {
    plan.sourceUrls = [...new Set(sources)];
  }

  return plan;
};

