  // Expanded State for Weeks
  const [expandedWeekIndex, setExpandedWeekIndex] = useState<number>(0);
  const [loadingWeek, setLoadingWeek] = useState<number | null>(null);

  // Streak State
  const [streak, setStreak] = useState(0);

