import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule, Flashcard } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// --- HYBRID MODEL STRATEGY ---
// 1. PRO Model: Used for complex reasoning, syllabus planning, and logic that requires high accuracy.
const MODEL_COMPLEX = "gemini-3-pro-preview";

// 2. FLASH Model: Used for interactive, low-latency tasks like chat, quizzes, and flashcards.
const MODEL_FAST = "gemini-3-flash-preview"; 

export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None'
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Format busy slots
  const busySlotsStr = busySlots.length > 0 
    ? busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime} (${b.label})`).join(', ')
    : "No fixed extra classes.";

  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  // Calculate current grade number for progression logic
  const gradeMatch = grade.match(/(\d+)/);
  const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : 0;

  const currentFormattedDate = today.toISOString().split('T')[0];

  // --- CONTEXT DETECTION LOGIC ---
  let examContextInstruction = "";
  const isLongDuration = daysUntilExam > 300; // Approx 10 months+

  if (isLongDuration) {
    if (currentGradeNum === 10 || currentGradeNum === 11) {
      examContextInstruction = `
