import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule, Flashcard } from '../types';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// --- SMART HYBRID STRATEGY ---
// 1. PRO: High reasoning, strict syllabus adherence. (Limit: 10 RPM on Free Tier)
const MODEL_COMPLEX = "gemini-3-pro-preview";

// 2. FLASH: High speed, unlimited fallback, great for interactive tasks.
const MODEL_FAST = "gemini-3-flash-preview"; 

/**
 * Helper: Smart Generator with Fallback
 * Tries the PRO model first. If it hits a rate limit (429) or error, 
 * it seamlessly falls back to the FLASH model so the user never sees an error.
 */
async function generateWithFallback(
    primaryModel: string, 
    fallbackModel: string, 
    params: any
) {
    try {
        // Attempt 1: Primary Model (e.g., Pro)
        return await ai.models.generateContent({
            ...params,
            model: primaryModel,
        });
    } catch (error: any) {
        // Check for Rate Limit (429) or Service Unavailable (503)
        // Also catching generic 500s which sometimes happen when Pro is overloaded
        const isQuotaError = 
            error.message?.includes('429') || 
            error.message?.includes('429') || 
            error.status === 429 ||
            error.status === 503;

        if (isQuotaError || fallbackModel) {
            console.warn(`⚠️ Primary model (${primaryModel}) limit hit or failed. Switching to Fallback (${fallbackModel})...`);
            // Attempt 2: Fallback Model (e.g., Flash)
            return await ai.models.generateContent({
                ...params,
                model: fallbackModel,
            });
        }
        throw error; // Re-throw if it's a different fatal error (like Auth fail)
    }
}

/**
 * Helper: Generate a batch of weeks
 */
async function generateRoadmapBatch(
    startWeekNumber: number,
    startDateStr: string,
    endDateStr: string,
    isFirstBatch: boolean,
    params: {
        grade: string,
        subjectsStr: string,
        restDay: string,
        examContextInstruction: string,
        langContext: string,
        currentFormattedDate: string,
        examDate: string
    }
): Promise<any> {
    const prompt = `
    You are a Strict Curriculum Expert for the National Institute of Education (NIE) Sri Lanka.
    Task: Create a **PARTIAL ROADMAP** for a specific time range: From ${startDateStr} to ${endDateStr}.
    This is Part ${isFirstBatch ? '1' : '2'} of a larger plan.

    Student Context:
    - Grade: ${params.grade}
    - Subjects: ${params.subjectsStr}
    - Rest Day: ${params.restDay}

    ${params.examContextInstruction}

    **CRITICAL SYLLABUS INSTRUCTIONS:**
    1. **Sequence:** The 'goal' for each week MUST correspond to the chronological order of the textbook.
    2. **Start Week:** The first week of this batch MUST be labeled as **Week ${startWeekNumber}**. Increment from there.

    **TOKEN LIMIT STRATEGY:**
    1. Output the list of weeks covering strictly ${startDateStr} to ${endDateStr}.
    2. ${isFirstBatch 
         ? "**Week " + startWeekNumber + " to Week " + (startWeekNumber + 3) + ":** Generate DETAILED 'sessions' arrays. For subsequent weeks in this batch, leave 'sessions' EMPTY []." 
         : "For ALL weeks in this batch, generate the 'weekNumber', 'startDate', 'endDate', 'phase', and 'goal', but leave the 'sessions' array EMPTY []. The user will generate details later."}

    Instructions:
    1. Use Google Search to find specific syllabus units for Sri Lanka NIE Grade ${params.grade}.
    2. Language: ${params.langContext}.
    3. Output JSON.
  `;

    const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
        contents: prompt,
        config: {
            tools: [{ googleSearch: {} }],
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    weeks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                weekNumber: { type: Type.INTEGER },
                                startDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                                endDate: { type: Type.STRING, description: "YYYY-MM-DD" },
                                phase: { type: Type.STRING, description: "Study Phase Name" },
                                goal: { type: Type.STRING, description: "Weekly Goal (Specific Syllabus Unit)" },
                                sessions: {
                                    type: Type.ARRAY,
                                    items: {
                                        type: Type.OBJECT,
                                        properties: {
                                            day: { type: Type.STRING },
                                            date: { type: Type.STRING, description: "YYYY-MM-DD" },
                                            subject: { type: Type.STRING },
                                            topic: { type: Type.STRING },
                                            unitNumber: { type: Type.STRING },
                                            technique: { type: Type.STRING },
                                            durationMinutes: { type: Type.NUMBER },
                                            startTime: { type: Type.STRING }
                                        },
                                        required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
                                    }
                                }
                            },
                            required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
                        }
                    },
                    tips: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING },
                        description: "General memory science tips"
                    }
                },
                required: ["weeks", "tips"]
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
        weeks: data.weeks,
        tips: data.tips,
        groundingChunks: response.candidates?.[0]?.groundingMetadata?.groundingChunks
    };
}


export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None'
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

  // Context & Instructions
  const langContext = language === 'si' 
    ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
    : "English language. Use terms strictly from English medium government textbooks.";

  const today = new Date();
  const exam = new Date(routine.examDate);
  const diffTime = Math.abs(exam.getTime() - today.getTime());
  const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  const gradeMatch = grade.match(/(\d+)/);
  const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : 0;

  const currentFormattedDate = today.toISOString().split('T')[0];

  // --- CONTEXT DETECTION LOGIC ---
  let examContextInstruction = "";
  const isLongDuration = daysUntilExam > 300; 

  if (isLongDuration) {
    if (currentGradeNum === 10 || currentGradeNum === 11) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Ordinary Level (O/L) Sri Lanka**
        - O/L covers Grade 10 & 11.
        - **Year 1:** Focus on Grade 10 syllabus (NIE).
        - **Year 2:** Focus on Grade 11 + Revision.
      `;
    } else if (currentGradeNum === 12 || currentGradeNum === 13) {
      examContextInstruction = `
        **EXAM CONTEXT: G.C.E. Advanced Level (A/L) Sri Lanka**
        - A/L covers Grade 12 & 13.
        - **Year 1:** Focus on Grade 12 syllabus (NIE).
        - **Year 2:** Focus on Grade 13 + Revision.
      `;
    } else {
      examContextInstruction = `
        **EXAM CONTEXT: Long Term Promotion**
        - Cover Grade ${currentGradeNum} content first.
        - Proceed to Grade ${currentGradeNum + 1} next year.
      `;
    }
  } else {
    examContextInstruction = `**EXAM CONTEXT:** Immediate/Short-term preparation for Grade ${currentGradeNum} exams.`;
  }

  const batchParams = {
      grade,
      subjectsStr,
      restDay,
      examContextInstruction,
      langContext,
      currentFormattedDate,
      examDate: routine.examDate
  };

  // --- SPLIT BATCH LOGIC ---
  // If duration is > 20 weeks (~5 months), split into 2 batches to avoid token limits.
  let mergedWeeks: any[] = [];
  let mergedTips: string[] = [];
  let collectedSources: string[] = [];

  if (daysUntilExam > 140) { // Approx 20 weeks
      // Calculate Midpoint
      const midTime = today.getTime() + (diffTime / 2);
      const midDate = new Date(midTime);
      const midDateStr = midDate.toISOString().split('T')[0];

      // Calculate approximate weeks in first batch
      const weeksInFirstBatch = Math.ceil((midTime - today.getTime()) / (1000 * 60 * 60 * 24 * 7));

      console.log("Splitting generation into 2 batches...");

      // Batch 1: Now -> Midpoint
      const batch1 = await generateRoadmapBatch(1, currentFormattedDate, midDateStr, true, batchParams);
      mergedWeeks = [...batch1.weeks];
      mergedTips = [...batch1.tips];

      if (batch1.groundingChunks) {
          const sources = batch1.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
          collectedSources.push(...sources);
      }

      // Small delay to be nice to the API rate limit
      await new Promise(resolve => setTimeout(resolve, 1500));

      // Batch 2: Midpoint -> Exam
      // Start week number is the last week of batch 1 + 1
      const lastWeekNum = batch1.weeks[batch1.weeks.length - 1]?.weekNumber || weeksInFirstBatch;
      const batch2 = await generateRoadmapBatch(lastWeekNum + 1, midDateStr, routine.examDate, false, batchParams);

      mergedWeeks = [...mergedWeeks, ...batch2.weeks];
      // We don't need to duplicate tips, so just keep batch 1 tips or merge unique ones.

      if (batch2.groundingChunks) {
          const sources = batch2.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
          collectedSources.push(...sources);
      }

  } else {
      // Short Duration: Single Call
      const batch = await generateRoadmapBatch(1, currentFormattedDate, routine.examDate, true, batchParams);
      mergedWeeks = batch.weeks;
      mergedTips = batch.tips;
      if (batch.groundingChunks) {
        const sources = batch.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
        collectedSources.push(...sources);
      }
  }

  // Construct Final Plan
  const plan: StudyPlan = {
    examDate: routine.examDate,
    weeks: mergedWeeks,
    tips: mergedTips,
    sourceUrls: [...new Set(collectedSources)]
  };

  return plan;
};

