  return JSON.parse(text) as QuizQuestion[];
};

export const getStudyAdvice = async (query: string, language: Language): Promise<string> => {
  if (!apiKey) throw new Error("API Key is missing");

  const langInstruction = language === 'si'
    ? "Provide the response in Sinhala language (Sinhala Unicode)."
    : "Provide the response in English language.";

  const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
    contents: `Provide concise, actionable, and scientific study advice for: "${query}". 
    IMPORTANT: ${langInstruction} Keep it friendly and encouraging for a Sri Lankan student. Keep it under 150 words.`,
  });

  return response.text || (language === 'si' ? "උපදෙස් ලබා ගැනීමට නොහැකි විය. කරුණාකර නැවත උත්සාහ කරන්න." : "Could not retrieve advice. Please try again.");
};

export const generateFlashcards = async (
    subject: string,
    topic: string,
    count: number,
    grade: string,
    language: Language
  ): Promise<Flashcard[]> => {
    if (!apiKey) throw new Error("API Key is missing");

    const langInstruction = language === 'si' 
      ? "Generate the front (term) and back (definition/answer) in Sinhala language (Sinhala Unicode)." 
      : "Generate the front (term) and back (definition/answer) in English language.";

    const prompt = `Generate ${count} study flashcards for Grade ${grade} students in Sri Lanka.
    Subject: ${subject}
    Topic: ${topic}

    INSTRUCTIONS:
    1. Base contents on NIE Sri Lanka Teacher's Guide.
    2. IMPORTANT: ${langInstruction}
    3. Keep the 'front' short (a term, concept, or question).
    4. Keep the 'back' clear and concise (definition or answer).
    5. Output JSON array.`;

    const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              front: { type: Type.STRING },
              back: { type: Type.STRING }
            },
            required: ["front", "back"]
          }
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response");
    return JSON.parse(text) as Flashcard[];
};

