export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None',
  onProgress?: (percent: number) => void // New Callback
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  // Local progress state management
  let currentProgress = 0;
  let progressTimer: NodeJS.Timeout | null = null;

  const updateProgress = (val: number) => {
      currentProgress = val;
      if (onProgress) onProgress(val);
  };

  // Simulates progress moving towards a target percentage
  const smoothProgressTo = (target: number) => {
      if (progressTimer) clearInterval(progressTimer);
      // Determine step based on distance to target to keep it somewhat consistent speed
      // But we want it to feel "working", so simple increment is usually fine.
      progressTimer = setInterval(() => {
          if (currentProgress < target) {
              // Add a bit of randomness to make it look "thoughtful"
              const increment = Math.random() > 0.7 ? 2 : 1;
              if (currentProgress + increment <= target) {
                  updateProgress(currentProgress + increment);
              }
          }
      }, 200);
  };

  const stopProgressSimulation = () => {
      if (progressTimer) clearInterval(progressTimer);
      progressTimer = null;
  };

  try {
      // 1. CHECK CACHE FIRST
      const cacheKey = getCacheKey({ subjects, hoursPerDay, focusArea, grade, language, routine });
      const cachedData = localStorage.getItem(cacheKey);
      if (cachedData) {
          stopProgressSimulation();
          updateProgress(100);
          console.log("Returning cached study plan");
          return JSON.parse(cachedData);
      }

      updateProgress(5);
      smoothProgressTo(15); // Start analyzing context

      const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

      const langContext = language === 'si' 
        ? "Sinhala language (Sinhala Unicode). Use terms strictly from Sinhala medium government textbooks." 
        : "English language. Use terms strictly from English medium government textbooks.";

      const today = new Date();
      const exam = new Date(routine.examDate);
      const diffTime = Math.abs(exam.getTime() - today.getTime());
      const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

      const gradeMatch = grade.match(/(\d+)/);
      const currentGradeNum = gradeMatch ? parseInt(gradeMatch[0]) : 0;

      const currentFormattedDate = today.toISOString().split('T')[0];

      // --- CONTEXT DETECTION LOGIC ---
      let examContextInstruction = "";
      const isLongDuration = daysUntilExam > 300; 

      if (isLongDuration) {
        if (currentGradeNum === 10 || currentGradeNum === 11) {
          examContextInstruction = `
            **EXAM CONTEXT: G.C.E. Ordinary Level (O/L) Sri Lanka**
            - O/L covers Grade 10 & 11.
            - **Year 1:** Focus on Grade 10 syllabus (NIE).
            - **Year 2:** Focus on Grade 11 + Revision.
          `;
        } else if (currentGradeNum === 12 || currentGradeNum === 13) {
          examContextInstruction = `
            **EXAM CONTEXT: G.C.E. Advanced Level (A/L) Sri Lanka**
            - A/L covers Grade 12 & 13.
            - **Year 1:** Focus on Grade 12 syllabus (NIE).
            - **Year 2:** Focus on Grade 13 + Revision.
          `;
        } else {
          examContextInstruction = `
            **EXAM CONTEXT: Long Term Promotion**
            - Cover Grade ${currentGradeNum} content first.
            - Proceed to Grade ${currentGradeNum + 1} next year.
          `;
        }
      } else {
        examContextInstruction = `**EXAM CONTEXT:** Immediate/Short-term preparation for Grade ${currentGradeNum} exams.`;
      }

      // Context analysis done
      stopProgressSimulation();
      updateProgress(15); // Set to base

      const batchParams = {
          grade,
          subjectsStr,
          restDay,
          examContextInstruction,
          langContext,
          currentFormattedDate,
          examDate: routine.examDate
      };

      // --- SPLIT BATCH LOGIC ---
      let mergedWeeks: any[] = [];
      let mergedTips: string[] = [];
      let collectedSources: string[] = [];

      if (daysUntilExam > 140) { // Approx 20 weeks
          // Calculate Midpoint
          const midTime = today.getTime() + (diffTime / 2);
          const midDate = new Date(midTime);
          const midDateStr = midDate.toISOString().split('T')[0];

          const weeksInFirstBatch = Math.ceil((midTime - today.getTime()) / (1000 * 60 * 60 * 24 * 7));

          console.log("Splitting generation into 2 batches...");

          // GENERATING BATCH 1
          smoothProgressTo(55); // Allow progress to crawl up to 55% while waiting

          const batch1 = await generateRoadmapBatch(1, currentFormattedDate, midDateStr, true, batchParams);

          stopProgressSimulation();
          updateProgress(60); // Checkpoint

          mergedWeeks = [...batch1.weeks];
          mergedTips = [...batch1.tips];

          if (batch1.groundingChunks) {
              const sources = batch1.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
              collectedSources.push(...sources);
          }

          // Small delay to be nice to the API rate limit
          smoothProgressTo(65);
          await new Promise(resolve => setTimeout(resolve, 1500));

          // GENERATING BATCH 2
          stopProgressSimulation();
          smoothProgressTo(90); // Allow progress to crawl up to 90% while waiting

          const lastWeekNum = batch1.weeks[batch1.weeks.length - 1]?.weekNumber || weeksInFirstBatch;
          const batch2 = await generateRoadmapBatch(lastWeekNum + 1, midDateStr, routine.examDate, false, batchParams);

          stopProgressSimulation();
          updateProgress(95);

          mergedWeeks = [...mergedWeeks, ...batch2.weeks];

          if (batch2.groundingChunks) {
              const sources = batch2.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
              collectedSources.push(...sources);
          }

      } else {
          // Short Duration: Single Call
          smoothProgressTo(85); // Allow progress to crawl up to 85%

          const batch = await generateRoadmapBatch(1, currentFormattedDate, routine.examDate, true, batchParams);

          stopProgressSimulation();
          updateProgress(90);

          mergedWeeks = batch.weeks;
          mergedTips = batch.tips;
          if (batch.groundingChunks) {
            const sources = batch.groundingChunks.map((c: any) => c.web?.uri).filter((u: any) => u);
            collectedSources.push(...sources);
          }
      }

      // Construct Final Plan
      const plan: StudyPlan = {
        examDate: routine.examDate,
        weeks: mergedWeeks,
        tips: mergedTips,
        sourceUrls: [...new Set(collectedSources)]
      };

      // 2. SAVE TO CACHE
      try {
        localStorage.setItem(cacheKey, JSON.stringify(plan));
      } catch (e) {
        console.warn("Cache full, skipping save");
      }

      updateProgress(100);
      return plan;
  } finally {
      stopProgressSimulation();
  }
};

