export const generateWeeklySessions = async (
    targetWeek: WeeklySchedule,
    subjects: Subject[],
    hoursPerDay: number,
    grade: string,
    language: Language,
    busySlots: BusySlot[],
    routine: UserRoutine,
    restDay: string
): Promise<any[]> => {
    if (!apiKey) throw new Error("API Key is missing");

    const subjectsStr = subjects.map(s => `${s.name}`).join(', ');
    const busySlotsStr = busySlots.map(b => `${b.day}: ${b.startTime}-${b.endTime}`).join(', ');

    const langContext = language === 'si' ? "Sinhala" : "English";

    const prompt = `
        Generate the DETAILED DAILY SCHEDULE for **Week ${targetWeek.weekNumber}**.

        Strict NIE Syllabus Context:
        - Grade: ${grade} (Sri Lanka Syllabus)
        - Target Unit/Goal: ${targetWeek.goal}
        - This schedule MUST strictly cover the sub-topics found in the NIE Teacher's Guide for this specific unit.

        Schedule Constraints:
        - Dates: ${targetWeek.startDate} to ${targetWeek.endDate}
        - Daily Target: ${hoursPerDay} hours
        - Busy Times: ${busySlotsStr}
        - Rest Day: ${restDay} (No heavy study on this day)
        - School Ends: ${routine.schoolEndTime}
        - Bedtime: ${routine.bedTime}

        Output: JSON Array of sessions for this week.
        Language: ${langContext}.
    `;

    const response = await generateWithFallback(MODEL_COMPLEX, MODEL_FAST, {
        contents: prompt,
        config: {
            tools: [{ googleSearch: {} }],
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                      day: { type: Type.STRING },
                      date: { type: Type.STRING },
                      subject: { type: Type.STRING },
                      topic: { type: Type.STRING },
                      unitNumber: { type: Type.STRING },
                      technique: { type: Type.STRING },
                      durationMinutes: { type: Type.NUMBER },
                      startTime: { type: Type.STRING }
                    },
                    required: ["day", "subject", "topic", "technique", "durationMinutes", "startTime"]
                }
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response");
    return JSON.parse(text);
}

