// Helper to normalize subject names (e.g., "Maths" -> "Mathematics")
export const normalizeSubject = (input: string): string => {
    const lower = input.toLowerCase();
    if (lower.includes('math') || lower.includes('ගණිත')) return 'Mathematics';
    if (lower.includes('sci') || lower.includes('විද්‍යා')) return 'Science';
    if (lower.includes('hist') || lower.includes('ඉතිහාස')) return 'History';
    if (lower.includes('eng') || lower.includes('ඉංග්‍රීසි')) return 'English';
    if (lower.includes('sin') || lower.includes('සිංහල')) return 'Sinhala';
    return input; // Return original if no match
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule, Flashcard } from '../types';
import { SYLLABUS_DB, normalizeSubject, SyllabusUnit } from '../data/syllabusDatabase';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// --- SMART HYBRID STRATEGY ---
const MODEL_COMPLEX = "gemini-3-pro-preview";
// Switched the 'Fast' model to be the primary for standard tasks to save money
const MODEL_FAST = "gemini-3-flash-preview"; 

const CACHE_PREFIX = 'nexus_plan_cache_';

/**
 * Generates a unique cache key.
 */
const getCacheKey = (params: any) => {
    const keyObj = {
        grade: params.grade,
        subjects: params.subjects.map((s: any) => s.name).sort().join(','),
        hours: params.hoursPerDay,
        examDate: params.routine.examDate,
        focus: params.focusArea,
        lang: params.language
    };
    return CACHE_PREFIX + btoa(encodeURIComponent(JSON.stringify(keyObj)));
};

async function generateWithFallback(
    primaryModel: string, 
    fallbackModel: string, 
    params: any
) {
    try {
        return await ai.models.generateContent({
            ...params,
            model: primaryModel,
        });
    } catch (error: any) {
        const isQuotaError = 
            error.message?.includes('429') || 
            error.status === 429 ||
            error.status === 503;

        if (isQuotaError || fallbackModel) {
            console.warn(`⚠️ Model (${primaryModel}) failed. Switching to (${fallbackModel})...`);
            return await ai.models.generateContent({
                ...params,
                model: fallbackModel,
            });
        }
        throw error;
    }
}

// --- LOCAL DB GENERATION (COST: 0 CREDITS) ---
function generateFromLocalDB(
    subjects: Subject[],
    grade: string,
    examDateStr: string,
    language: Language
): { weeks: any[], tips: string[], isLocal: boolean } | null {

    // 1. Check if we have data for this grade
    const gradeData = SYLLABUS_DB[grade];
    if (!gradeData) return null;

    // 2. Check if we have data for at least one subject
    const relevantSyllabi: { name: string, units: SyllabusUnit[] }[] = [];

    subjects.forEach(sub => {
        const normalizedName = normalizeSubject(sub.name);
        if (gradeData[normalizedName]) {
            relevantSyllabi.push({ name: sub.name, units: gradeData[normalizedName] });
        }
    });

    if (relevantSyllabi.length === 0) return null; // Fallback to AI if no local data matches

    // 3. Mathematical Distribution
    const today = new Date();
    const examDate = new Date(examDateStr);
    const diffTime = Math.abs(examDate.getTime() - today.getTime());
    const totalWeeks = Math.ceil(diffTime / (1000 * 60 * 60 * 24 * 7));

    const weeks = [];
    let currentWeekStart = new Date();

    // Loop through available weeks
    for (let i = 1; i <= totalWeeks; i++) {
        const weekStart = new Date(currentWeekStart);
        const weekEnd = new Date(currentWeekStart);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Round-robin assign units from subjects
        // For Week 1: Subject A Unit 1, Subject B Unit 1
        // For Week 2: Subject A Unit 2, Subject B Unit 2...
        const weeklyGoals: string[] = [];

        relevantSyllabi.forEach(syllabus => {
            // Logic: If we have 10 units and 20 weeks, we do one unit every 2 weeks.
            // If we have 20 units and 10 weeks, we do 2 units per week.
            const unitIndex = Math.floor(((i - 1) / totalWeeks) * syllabus.units.length);

            if (syllabus.units[unitIndex]) {
                const u = syllabus.units[unitIndex];
                weeklyGoals.push(`${syllabus.name}: ${u.unit}`);
            }
        });

        // Determine Phase
        let phase = "Foundation";
        if (i > totalWeeks * 0.6) phase = "Consolidation";
        if (i > totalWeeks * 0.85) phase = "Final Revision";

        weeks.push({
            weekNumber: i,
            startDate: weekStart.toISOString().split('T')[0],
            endDate: weekEnd.toISOString().split('T')[0],
            phase: phase,
            goal: weeklyGoals.length > 0 ? weeklyGoals.join(" | ") : "Review & Practice",
            sessions: [] // Empty sessions, to be lazy loaded
        });

        // Advance date
        currentWeekStart.setDate(currentWeekStart.getDate() + 7);
    }

    const tips = language === 'si' 
        ? ["කෙටි විවේක ලබා ගනිමින් පාඩම් කරන්න.", "පසුගිය විභාග ප්‍රශ්න පත්‍ර සාකච්ඡා කරන්න."]
        : ["Take short breaks using Pomodoro.", "Practice past papers regularly."];

    return { weeks, tips, isLocal: true };
}


// --- AI GENERATION ---
async function generateRoadmapBatch(
    startWeekNumber: number,
    startDateStr: string,
    endDateStr: string,
    isFirstBatch: boolean,
    params: {
        grade: string,
        subjectsStr: string,
        restDay: string,
        examContextInstruction: string,
        langContext: string,
        currentFormattedDate: string,
        examDate: string
    }
): Promise<any> {
    const prompt = `
    You are a Curriculum Expert for Sri Lanka (NIE).
    Task: Create a **PARTIAL ROADMAP** (${startDateStr} to ${endDateStr}).
    Part ${isFirstBatch ? '1' : '2'} of plan.

    Context:
    - Grade: ${params.grade}
    - Subjects: ${params.subjectsStr}

    ${params.examContextInstruction}

    Strict Rules:
    1. **Sequence:** Follow textbook order.
    2. **Start:** Week ${startWeekNumber}.

    **TOKEN SAVING:**
    1. Output JSON only.
    2. ${isFirstBatch 
         ? "**Week " + startWeekNumber + " to " + (startWeekNumber + 1) + " ONLY:** Generate detailed 'sessions'. ALL other weeks: empty 'sessions' []." 
         : "ALL weeks: empty 'sessions' []."}

    Output JSON: { "weeks": [{ weekNumber, startDate, endDate, phase, goal, sessions: [] }], "tips": [] }
  `;

    // CHANGED: Use Flash model primarily to save credits
    const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
        contents: prompt,
        config: {
            // Removed googleSearch tool to save credits/latency for pure structure generation
            // unless absolutely necessary. Flash has good internal knowledge of standard subjects.
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    weeks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                weekNumber: { type: Type.INTEGER },
                                startDate: { type: Type.STRING },
                                endDate: { type: Type.STRING },
                                phase: { type: Type.STRING },
                                goal: { type: Type.STRING },
                                sessions: {
                                    type: Type.ARRAY,
                                    items: {
                                        type: Type.OBJECT,
                                        properties: {
                                            day: { type: Type.STRING },
                                            subject: { type: Type.STRING },
                                            topic: { type: Type.STRING },
                                            technique: { type: Type.STRING },
                                            durationMinutes: { type: Type.NUMBER },
                                            startTime: { type: Type.STRING }
                                        },
                                        required: ["day", "subject", "topic"]
                                    }
                                }
                            },
                            required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
                        }
                    },
                    tips: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
        weeks: data.weeks,
