// Helper to normalize subject names (e.g., "Maths" -> "Mathematics")
export const normalizeSubject = (input: string): string => {
    const lower = input.toLowerCase();
    if (lower.includes('math') || lower.includes('ගණිත')) return 'Mathematics';
    if (lower.includes('sci') || lower.includes('විද්‍යා')) return 'Science';
    if (lower.includes('hist') || lower.includes('ඉතිහාස')) return 'History';
    if (lower.includes('eng') || lower.includes('ඉංග්‍රීසි')) return 'English';
    if (lower.includes('sin') || lower.includes('සිංහල')) return 'Sinhala';
    if (lower.includes('bud') || lower.includes('බුද්ධ')) return 'Buddhism';
    return input; // Return original if no match
};

import { GoogleGenAI, Type } from "@google/genai";
import { Subject, StudyPlan, QuizQuestion, Language, BusySlot, UserRoutine, WeeklySchedule, Flashcard } from '../types';
import { SYLLABUS_DB, normalizeSubject, SyllabusUnit, GradeSyllabus } from '../data/syllabusDatabase';
import { db } from './firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// --- SMART HYBRID STRATEGY ---
const MODEL_COMPLEX = "gemini-3-pro-preview";
// Switched the 'Fast' model to be the primary for standard tasks to save money
const MODEL_FAST = "gemini-3-flash-preview"; 

const CACHE_PREFIX = 'nexus_plan_cache_';

/**
 * Generates a unique cache key.
 */
const getCacheKey = (params: any) => {
    const keyObj = {
        grade: params.grade,
        subjects: params.subjects.map((s: any) => s.name).sort().join(','),
        hours: params.hoursPerDay,
        examDate: params.routine.examDate,
        focus: params.focusArea,
        lang: params.language
    };
    return CACHE_PREFIX + btoa(encodeURIComponent(JSON.stringify(keyObj)));
};

/**
 * Helper to create safe Firestore Document IDs from user input
 * Removes special characters and spaces
 */
const createDocId = (...parts: string[]) => {
    return parts
        .map(p => p.toLowerCase().trim().replace(/[^a-z0-9\u0D80-\u0DFF]+/gi, '_')) // Supports Sinhala chars + alphanumeric
        .join('__');
};

async function generateWithFallback(
    primaryModel: string, 
    fallbackModel: string, 
    params: any
) {
    try {
        return await ai.models.generateContent({
            ...params,
            model: primaryModel,
        });
    } catch (error: any) {
        const isQuotaError = 
            error.message?.includes('429') || 
            error.status === 429 ||
            error.status === 503;

        if (isQuotaError || fallbackModel) {
            console.warn(`⚠️ Model (${primaryModel}) failed. Switching to (${fallbackModel})...`);
            return await ai.models.generateContent({
                ...params,
                model: fallbackModel,
            });
        }
        throw error;
    }
}

// --- HYBRID DB GENERATION (Firebase -> Local -> AI) ---
async function generateFromDB(
    subjects: Subject[],
    grade: string,
    examDateStr: string,
    language: Language
): Promise<{ weeks: any[], tips: string[], isLocal: boolean } | null> {

    let gradeData: GradeSyllabus | undefined = undefined;

    // 1. Try Fetching from Firebase Firestore
    if (db) {
        try {
            // Using the grade string as the document ID (e.g., "10 ශ්‍රේණිය (Grade 10)")
            const docRef = doc(db, "syllabus", grade);
            const docSnap = await getDoc(docRef);

            if (docSnap.exists()) {
                console.log("✅ Fetched syllabus from Firebase Firestore");
                gradeData = docSnap.data() as GradeSyllabus;
            }
        } catch (e) {
            console.warn("⚠️ Firebase fetch failed (check config/internet). Falling back to local DB.", e);
        }
    }

    // 2. Fallback to Local DB if Firebase failed or data missing
    if (!gradeData) {
        console.log("ℹ️ Using Local Syllabus Database fallback");
        gradeData = SYLLABUS_DB[grade];
    }

    if (!gradeData) return null; // Both failed, use AI

    // 3. Process the Data (Mathematical Distribution)
    const relevantSyllabi: { name: string, units: SyllabusUnit[] }[] = [];

    subjects.forEach(sub => {
        const normalizedName = normalizeSubject(sub.name);
        // Check if gradeData has data for this subject
        if (gradeData && gradeData[normalizedName]) {
            relevantSyllabi.push({ name: sub.name, units: gradeData[normalizedName] });
        }
    });

    if (relevantSyllabi.length === 0) return null; 

    const today = new Date();
    const examDate = new Date(examDateStr);
    const diffTime = Math.abs(examDate.getTime() - today.getTime());
    const totalWeeks = Math.ceil(diffTime / (1000 * 60 * 60 * 24 * 7));

    const weeks = [];
    let currentWeekStart = new Date();

    // Loop through available weeks
    for (let i = 1; i <= totalWeeks; i++) {
        const weekStart = new Date(currentWeekStart);
        const weekEnd = new Date(currentWeekStart);
        weekEnd.setDate(weekEnd.getDate() + 6);

        // Round-robin assign units
        const weeklyGoals: string[] = [];

        relevantSyllabi.forEach(syllabus => {
            const unitIndex = Math.floor(((i - 1) / totalWeeks) * syllabus.units.length);
            if (syllabus.units[unitIndex]) {
                const u = syllabus.units[unitIndex];
                weeklyGoals.push(`${syllabus.name}: ${u.unit}`);
            }
        });

        let phase = "Foundation";
        if (i > totalWeeks * 0.6) phase = "Consolidation";
        if (i > totalWeeks * 0.85) phase = "Final Revision";

        weeks.push({
            weekNumber: i,
            startDate: weekStart.toISOString().split('T')[0],
            endDate: weekEnd.toISOString().split('T')[0],
            phase: phase,
            goal: weeklyGoals.length > 0 ? weeklyGoals.join(" | ") : "Review & Practice",
            sessions: [] 
        });

        currentWeekStart.setDate(currentWeekStart.getDate() + 7);
    }

    const tips = language === 'si' 
        ? ["කෙටි විවේක ලබා ගනිමින් පාඩම් කරන්න.", "පසුගිය විභාග ප්‍රශ්න පත්‍ර සාකච්ඡා කරන්න."]
        : ["Take short breaks using Pomodoro.", "Practice past papers regularly."];

    return { weeks, tips, isLocal: true };
}


// --- AI GENERATION ---
async function generateRoadmapBatch(
    startWeekNumber: number,
    startDateStr: string,
    endDateStr: string,
    isFirstBatch: boolean,
    params: {
        grade: string,
        subjectsStr: string,
        restDay: string,
        examContextInstruction: string,
        langContext: string,
        currentFormattedDate: string,
        examDate: string
    }
): Promise<any> {
    const prompt = `
    You are a Curriculum Expert for Sri Lanka (NIE).
    Task: Create a **PARTIAL ROADMAP** (${startDateStr} to ${endDateStr}).
    Part ${isFirstBatch ? '1' : '2'} of plan.

    Context:
    - Grade: ${params.grade}
    - Subjects: ${params.subjectsStr}

    ${params.examContextInstruction}

    Strict Rules:
    1. **Sequence:** Follow textbook order.
    2. **Start:** Week ${startWeekNumber}.

    **TOKEN SAVING:**
    1. Output JSON only.
    2. ${isFirstBatch 
         ? "**Week " + startWeekNumber + " to " + (startWeekNumber + 1) + " ONLY:** Generate detailed 'sessions'. ALL other weeks: empty 'sessions' []." 
         : "ALL weeks: empty 'sessions' []."}

    Output JSON: { "weeks": [{ weekNumber, startDate, endDate, phase, goal, sessions: [] }], "tips": [] }
  `;

    // CHANGED: Use Flash model primarily to save credits
    const response = await generateWithFallback(MODEL_FAST, MODEL_COMPLEX, {
        contents: prompt,
        config: {
            // Removed googleSearch tool to save credits/latency for pure structure generation
            // unless absolutely necessary. Flash has good internal knowledge of standard subjects.
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    weeks: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                weekNumber: { type: Type.INTEGER },
                                startDate: { type: Type.STRING },
                                endDate: { type: Type.STRING },
                                phase: { type: Type.STRING },
                                goal: { type: Type.STRING },
                                sessions: {
                                    type: Type.ARRAY,
                                    items: {
                                        type: Type.OBJECT,
                                        properties: {
                                            day: { type: Type.STRING },
                                            subject: { type: Type.STRING },
                                            topic: { type: Type.STRING },
                                            technique: { type: Type.STRING },
                                            durationMinutes: { type: Type.NUMBER },
                                            startTime: { type: Type.STRING }
                                        },
                                        required: ["day", "subject", "topic"]
                                    }
                                }
                            },
                            required: ["weekNumber", "startDate", "endDate", "phase", "goal", "sessions"]
                        }
                    },
                    tips: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            }
        }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    const data = JSON.parse(text);
    return {
        weeks: data.weeks,
        tips: data.tips,
        groundingChunks: [] // Disabled grounding for roadmap to save tokens
    };
}


export const generateStudyPlan = async (
  subjects: Subject[],
  hoursPerDay: number,
  focusArea: string,
  grade: string,
  language: Language,
  busySlots: BusySlot[] = [],
  routine: UserRoutine,
  restDay: string = 'None',
  onProgress?: (percent: number) => void
): Promise<StudyPlan> => {
  if (!apiKey) throw new Error("API Key is missing");

  let currentProgress = 0;
  let progressTimer: any | null = null;

  const updateProgress = (val: number) => {
      currentProgress = val;
      if (onProgress) onProgress(val);
  };

  const smoothProgressTo = (target: number) => {
      if (progressTimer) clearInterval(progressTimer);
      progressTimer = setInterval(() => {
          if (currentProgress < target) {
              const increment = Math.random() > 0.7 ? 2 : 1;
              if (currentProgress + increment <= target) {
                  updateProgress(currentProgress + increment);
              }
          }
      }, 200);
  };

  const stopProgressSimulation = () => {
      if (progressTimer) clearInterval(progressTimer);
      progressTimer = null;
  };

  try {
      const cacheKey = getCacheKey({ subjects, hoursPerDay, focusArea, grade, language, routine });
      const cachedData = localStorage.getItem(cacheKey);
      if (cachedData) {
          stopProgressSimulation();
          updateProgress(100);
          return JSON.parse(cachedData);
      }

      updateProgress(5);
      smoothProgressTo(20);

      // --- STRATEGY 1: TRY DATABASE (Firebase -> Local) (0 Credits) ---
      const dbPlan = await generateFromDB(subjects, grade, routine.examDate, language);

      if (dbPlan) {
        stopProgressSimulation();
        updateProgress(100);

        const plan: StudyPlan = {
            examDate: routine.examDate,
            weeks: dbPlan.weeks,
            tips: dbPlan.tips,
            sourceUrls: []
        };

        // Save to cache
        try { localStorage.setItem(cacheKey, JSON.stringify(plan)); } catch (e) {}
        return plan;
      }

      // --- STRATEGY 2: AI FALLBACK (Use Flash Model) ---
      console.log("DB miss. Using AI (Flash Model)...");

      const subjectsStr = subjects.map(s => `${s.name} (${s.difficulty})`).join(', ');

      const langContext = language === 'si' 
        ? "Sinhala language. Use Sinhala terms." 
        : "English language.";

      const today = new Date();
      const exam = new Date(routine.examDate);
      const diffTime = Math.abs(exam.getTime() - today.getTime());
      const daysUntilExam = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
      const currentFormattedDate = today.toISOString().split('T')[0];

      let examContextInstruction = `Target: Grade ${grade}`;

      // Context analysis done
      stopProgressSimulation();
      updateProgress(25);

      const batchParams = {
          grade,
          subjectsStr,
          restDay,
          examContextInstruction,
          langContext,
          currentFormattedDate,
          examDate: routine.examDate
      };

      let mergedWeeks: any[] = [];
      let mergedTips: string[] = [];

      if (daysUntilExam > 140) { 
          // Split into batches to avoid output token limits
          const midTime = today.getTime() + (diffTime / 2);
          const midDateStr = new Date(midTime).toISOString().split('T')[0];
          const weeksInFirstBatch = Math.ceil((midTime - today.getTime()) / (1000 * 60 * 60 * 24 * 7));

          smoothProgressTo(55);
          const batch1 = await generateRoadmapBatch(1, currentFormattedDate, midDateStr, true, batchParams);

          stopProgressSimulation();
          updateProgress(60);
          mergedWeeks = [...batch1.weeks];
          mergedTips = [...batch1.tips];

          smoothProgressTo(65);
          await new Promise(resolve => setTimeout(resolve, 1000));

          smoothProgressTo(90);
          const lastWeekNum = batch1.weeks[batch1.weeks.length - 1]?.weekNumber || weeksInFirstBatch;
          const batch2 = await generateRoadmapBatch(lastWeekNum + 1, midDateStr, routine.examDate, false, batchParams);

          stopProgressSimulation();
          updateProgress(95);
          mergedWeeks = [...mergedWeeks, ...batch2.weeks];

      } else {
          smoothProgressTo(85); 
          const batch = await generateRoadmapBatch(1, currentFormattedDate, routine.examDate, true, batchParams);
          stopProgressSimulation();
          updateProgress(90);
          mergedWeeks = batch.weeks;
          mergedTips = batch.tips;
      }

      const plan: StudyPlan = {
        examDate: routine.examDate,
        weeks: mergedWeeks,
        tips: mergedTips,
        sourceUrls: []
      };

      try {
        localStorage.setItem(cacheKey, JSON.stringify(plan));
      } catch (e) {
        console.warn("Cache full");
      }

      updateProgress(100);
      return plan;
  } finally {
      stopProgressSimulation();
  }
};

