    const text = response.text;
    if (!text) throw new Error("No response");
    return JSON.parse(text);
}


export const generateQuiz = async (
  subject: string, 
  topic: string, 
  subTopic: string, 
  questionCount: number,
  difficulty: string, 
  grade: string, 
  language: Language
): Promise<QuizQuestion[]> => {
  if (!apiKey) throw new Error("API Key is missing");

  // 1. Try to fetch from DB first (Save Credits)
  if (db) {
    try {
        const docId = createDocId(grade, subject, topic || 'general', difficulty, language);
        const docRef = doc(db, 'quizzes', docId);
        const docSnap = await getDoc(docRef);

        if (docSnap.exists()) {
            console.log("✅ Quiz fetched from Firebase (Saved Credits!)");
            return docSnap.data().questions as QuizQuestion[];
        }
    } catch (e) {
        console.warn("Quiz fetch error", e);
    }
