        "6 ශ්‍රේණිය (Grade 6)", "7 ශ්‍රේණිය (Grade 7)", "8 ශ්‍රේණිය (Grade 8)", 
        "9 ශ්‍රේණිය (Grade 9)", "10 ශ්‍රේණිය (Grade 10)", "11 ශ්‍රේණිය (Grade 11)",
        "12 ශ්‍රේණිය (Grade 12)", "13 ශ්‍රේණිය (Grade 13)"
    ];

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            if (event.target?.result) {
                setJsonContent(event.target.result as string);
                setLogs(prev => [...prev, `File loaded: ${file.name}`]);
            }
        };
        reader.readAsText(file);
    };

    const addLog = (msg: string) => setLogs(prev => [...prev, `[${new Date().toLocaleTimeString()}] ${msg}`]);

    const handleUpload = async () => {
        if (!db) {
            addLog("Error: Firebase not initialized.");
            return;
        }
        if (!jsonContent) {
            addLog("Error: No JSON content loaded.");
            return;
        }

        setIsUploading(true);
        const batch = writeBatch(db);
        let opCount = 0;

        try {
            const data = JSON.parse(jsonContent);

            if (uploadType === 'syllabus') {
                // Upload Full Syllabus Structure
                // Expected JSON: { "Mathematics": [...], "Science": [...] }
                const docRef = doc(db, 'syllabus', grade);
                batch.set(docRef, data);
                opCount++;
                addLog(`Queued Syllabus for ${grade}`);
            } 
            else if (uploadType === 'pack') {
                // Upload Study Pack (Quiz + Flashcards)
                // Expected JSON: { "Unit 1": { quiz: [], flashcards: [] }, ... }

                if (!subject) {
                    addLog("Error: Subject is required for Study Pack upload.");
                    setIsUploading(false);
                    return;
                }

                for (const [unitName, content] of Object.entries(data)) {
                    const unitData = content as any;
                    const safeUnitName = unitName.replace(/Unit \d+[:.]\s*/i, ''); // Clean "Unit 1: " prefix if wanted, but simpler to keep it or use logic

                    // 1. Upload Quiz
                    if (unitData.quiz && Array.isArray(unitData.quiz)) {
                        const quizId = createDocId(grade, subject, safeUnitName, 'medium', language);
                        const quizRef = doc(db, 'quizzes', quizId);
                        batch.set(quizRef, { 
                            questions: unitData.quiz,
                            createdAt: new Date().toISOString(),
                            source: 'admin_upload'
                        });
                        opCount++;
                        addLog(`Queued Quiz: ${subject} - ${unitName}`);
                    }

                    // 2. Upload Flashcards
                    if (unitData.flashcards && Array.isArray(unitData.flashcards)) {
                        const flashId = createDocId(grade, subject, safeUnitName, language);
                        const flashRef = doc(db, 'flashcards', flashId);
                        batch.set(flashRef, { 
                            cards: unitData.flashcards,
                            createdAt: new Date().toISOString(),
                            source: 'admin_upload'
                        });
                        opCount++;
                        addLog(`Queued Flashcards: ${subject} - ${unitName}`);
                    }
                }
            }

            if (opCount > 0) {
                await batch.commit();
                addLog(`✅ SUCCESS: Committed ${opCount} documents to Firestore.`);
                setJsonContent(''); // Clear after success
            } else {
                addLog("⚠️ Warning: No valid data found to upload.");
            }

        } catch (e: any) {
            console.error(e);
            addLog(`❌ ERROR: ${e.message}`);
        } finally {
            setIsUploading(false);
        }
    };

    return (
        <div className="max-w-4xl mx-auto p-6">
            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
                <div className="flex items-center gap-3 mb-6 border-b border-slate-100 pb-4">
                    <div className="bg-indigo-100 p-2 rounded-lg">
                        <Database className="w-6 h-6 text-indigo-600" />
                    </div>
                    <div>
                        <h2 className="text-xl font-bold text-slate-800">Bulk Data Upload</h2>
                        <p className="text-sm text-slate-500">Upload JSON files to populate the app database.</p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {/* Settings Column */}
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Upload Type</label>
                            <div className="flex gap-2">
                                <button 
                                    onClick={() => setUploadType('pack')}
                                    className={`flex-1 py-2 px-3 rounded-lg text-sm border ${uploadType === 'pack' ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'border-slate-200 text-slate-600'}`}
                                >
                                    Study Pack (Quiz/Cards)
                                </button>
                                <button 
                                    onClick={() => setUploadType('syllabus')}
                                    className={`flex-1 py-2 px-3 rounded-lg text-sm border ${uploadType === 'syllabus' ? 'bg-indigo-50 border-indigo-200 text-indigo-700' : 'border-slate-200 text-slate-600'}`}
                                >
                                    Syllabus Structure
                                </button>
                            </div>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Grade</label>
                            <select 
                                value={grade} 
                                onChange={(e) => setGrade(e.target.value)}
                                className="w-full p-2.5 rounded-lg border border-slate-300 text-sm bg-white"
                            >
                                {grades.map(g => <option key={g} value={g}>{g}</option>)}
                            </select>
                        </div>

                        <div>
                            <label className="block text-sm font-medium text-slate-700 mb-1">Language</label>
                            <select 
                                value={language} 
                                onChange={(e) => setLanguage(e.target.value as any)}
                                className="w-full p-2.5 rounded-lg border border-slate-300 text-sm bg-white"
                            >
                                <option value="si">Sinhala</option>
                                <option value="en">English</option>
                            </select>
                        </div>

                        {uploadType === 'pack' && (
                            <div className="animate-fade-in">
                                <label className="block text-sm font-medium text-slate-700 mb-1">Subject</label>
                                <input 
                                    type="text" 
                                    value={subject}
                                    onChange={(e) => setSubject(e.target.value)}
                                    placeholder="Ex: Science"
                                    className="w-full p-2.5 rounded-lg border border-slate-300 text-sm"
                                />
                            </div>
                        )}

                        <div className="pt-2">
                            <label className="block text-sm font-medium text-slate-700 mb-2">Select JSON File</label>
                            <div className="border-2 border-dashed border-slate-300 rounded-xl p-6 flex flex-col items-center justify-center text-center cursor-pointer hover:bg-slate-50 transition-colors relative">
                                <input 
                                    type="file" 
                                    accept=".json"
                                    onChange={handleFileChange}
                                    className="absolute inset-0 opacity-0 cursor-pointer"
                                />
                                <FileJson className="w-8 h-8 text-slate-400 mb-2" />
                                <span className="text-sm text-slate-600 font-medium">Click to upload JSON</span>
                                {jsonContent && <span className="text-xs text-green-600 mt-1 font-bold flex items-center gap-1"><CheckCircle className="w-3 h-3" /> File Selected</span>}
                            </div>
                        </div>

                        <Button 
                            onClick={handleUpload} 
                            disabled={isUploading || !jsonContent}
                            className="w-full mt-4"
                        >
                            {isUploading ? 'Uploading...' : 'Start Upload'}
                        </Button>
                    </div>

                    {/* Logs Column */}
                    <div className="bg-slate-900 rounded-xl p-4 text-xs font-mono text-slate-300 overflow-y-auto max-h-[500px] border border-slate-800">
                        <div className="flex items-center gap-2 text-slate-500 mb-3 border-b border-slate-800 pb-2">
                            <FileText className="w-4 h-4" />
                            <span>Process Logs</span>
                        </div>
                        {logs.length === 0 ? (
                            <div className="text-slate-600 italic">Waiting for input...</div>
                        ) : (
                            <div className="space-y-1">
                                {logs.map((log, i) => (
                                    <div key={i} className={log.includes('ERROR') ? 'text-red-400' : log.includes('SUCCESS') ? 'text-green-400 font-bold' : ''}>
                                        {log}
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};

