                  </button>
                ))}
              </nav>

              <div className="h-8 w-px bg-slate-200 hidden sm:block"></div>

              {/* Action Buttons */}
              <div className="flex items-center gap-2">
                {/* Admin Button (Hidden from main nav but accessible here) */}
                <button 
                    onClick={() => setActiveTab('admin')}
                    className={`p-2 rounded-xl border transition-colors ${activeTab === 'admin' ? 'bg-indigo-50 border-indigo-200 text-indigo-600' : 'bg-white border-slate-200 text-slate-400 hover:text-indigo-600'}`}
                    title="Database Admin"
                >
                    <Database className="w-4 h-4" />
